const e="文字の式",t=191,n=[{id:"P0-MOJI-001",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"6b×7",answer:"42b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字式のかけ算では、数どうし・文字どうしをそれぞれまとめて計算するよ。6b×7なら、数の6と7をかけて、文字bはそのまま残すんだ。",next:"n2"},{id:"n2",type:"check",question:"6×7の計算結果は？",choices:["42","48（九九を間違えた）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"6×7は九九で確認しよう。6を7回たす、あるいは6×7の九九そのままで42になるよ。",next:"n2"},{id:"n3",type:"check",question:"6×7=42を計算した後、答えの書き方として正しいのはどっち？",choices:["42b（数が前、文字が後ろ）","b42（文字が前、数が後ろ）"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"文字式では「数を前、文字を後ろ」に書く約束があるよ。42とbが計算できたら、42bの順で書くんだったね。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：文字式のかけ算は「数どうしを先に計算し、数を前・文字を後ろに書く」がルールだよ。",next:"end"}]}},{id:"P0-MOJI-002",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"8×(-0.9y)",answer:"-7.2y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"8×(-0.9y)は、数どうし8と-0.9をかけて、文字yはそのまま残すよ。まず符号を考えよう。正×負はどうなる？",next:"n2"},{id:"n2",type:"check",question:"正の数×負の数の符号はどうなる？",choices:["正になる","負になる"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"正×負は必ず負になるよ。符号を忘れずにつけよう。",next:"n2"},{id:"n3",type:"explain",text:"8×0.9=7.2で、符号は負だから-7.2。これに文字yをつけて-7.2yだね。",next:"n4"},{id:"n4",type:"check",question:"8×0.9=7.2まで計算したあと、符号をつけ忘れるとどうなる？",choices:["7.2yになり不正解","-7.2yのまま正解"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を忘れると答えが変わってしまうよ。計算の最後に必ず符号を確認する習慣をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：数どうしの計算と符号決定を別々にせず、最後まで符号を意識しよう。",next:"end"}]}},{id:"P0-MOJI-003",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"5y×(-3)",answer:"-15y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5y×(-3)は、数どうし5と-3をかけて、文字yを最後につけるよ。まず5×3を計算しよう。",next:"n2"},{id:"n2",type:"check",question:"5×3の計算結果は？",choices:["8（足し算してしまった）","15（正しくかけ算した）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"×は「かけ算」だよ。5×3は5を3回たす、つまり5+5+5=15になるよ。",next:"n2"},{id:"n3",type:"check",question:"正の数×負の数の符号はどうなる？",choices:["正になる","負になる"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"正×負は必ず負になるよ。15にマイナスをつけて-15にしよう。",next:"n3"},{id:"n4",type:"explain",text:"5×(-3)=-15に文字yをつけて-15yが答えだね。",next:"end"}]}},{id:"P0-MOJI-004",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-1)×7a",answer:"-7a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-1)×7aは、数どうしの(-1)と7をかけて、文字aは最後につけるよ。まず(-1)×7を計算しよう。",next:"n2"},{id:"n2",type:"check",question:"(-1)×7の計算結果は？",choices:["-7","7を無視して-1aのまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"(-1)は7aの前にある「かける数」だから、7もちゃんとかけ算するよ。(-1)×7=-7だね。",next:"n2"},{id:"n3",type:"check",question:"係数が1になったとき、書き方として正しいのは？",choices:["1aと数字の1を書く","aと1を省略して書く（符号はそのまま残す）"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"係数1は省略するのが約束だけど、マイナスの符号は省略しないよ。-1aなら-aと書くんだ。",next:"n3"},{id:"n4",type:"explain",text:"(-1)×7=-7に文字aをつけて-7aが答え。符号のマイナスは最後まで残そう。",next:"end"}]}},{id:"P0-MOJI-005",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-8)×(-4b)",answer:"32b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-8)×(-4b)は数どうし(-8)と(-4)をかけて、文字bを最後につけるよ。まず符号を確認しよう。",next:"n2"},{id:"n2",type:"check",question:"負の数×負の数の符号はどうなる？",choices:["負のまま残る（マイナスが1個残る）","正になる"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナスは「独立して1個残る」ものではなく、2個のマイナスをかけると打ち消し合って正になるよ。負×負＝正、と覚えよう。",next:"n2"},{id:"n3",type:"check",question:"8×4の計算結果は？",choices:["32","12（足し算してしまった）"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"×はかけ算だよ。8×4は8を4回たす、8+8+8+8=32になるよ。",next:"n3"},{id:"n4",type:"explain",text:"8×4=32で、符号は正だから32。文字bをつけて32bが答えだね。",next:"end"}]}},{id:"P0-MOJI-006",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"9x×(-7)",answer:"-63x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"9x×(-7)は、数どうし9と-7をかけて、文字xを最後につけるよ。まず9×7を計算しよう。",next:"n2"},{id:"n2",type:"check",question:"9×7の計算結果は？",choices:["16（足し算してしまった）","63（正しくかけ算した）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"×はかけ算だよ。9×7は九九で確認すると63になるよ。",next:"n2"},{id:"n3",type:"check",question:"正の数×負の数の符号はどうなる？",choices:["正のまま","負になる"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"正×負は必ず負になるよ。63にマイナスをつけて-63にしよう。",next:"n3"},{id:"n4",type:"explain",text:"9×(-7)=-63に文字xをつけて-63xが答えだね。",next:"end"}]}},{id:"P0-MOJI-007",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-15a)×4",answer:"-60a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-15a)×4は数どうし(-15)と4をかけて、文字aを最後につけるよ。まず15×4を計算しよう。",next:"n2"},{id:"n2",type:"check",question:"15×4の計算結果は？",choices:["59（暗算でずれてしまった）","60（正しく計算した）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"急いで暗算するとずれやすいよ。15×4は15×2×2=30×2=60、と2段階に分けると確実だよ。",next:"n2"},{id:"n3",type:"check",question:"負の数×正の数の符号はどうなる？",choices:["負になる","正になる"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"負×正は負になるよ。60にマイナスをつけて-60にしよう。",next:"n3"},{id:"n4",type:"explain",text:"(-15)×4=-60に文字aをつけて-60aが答えだね。",next:"end"}]}},{id:"P0-MOJI-008",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"32×3/4 y",answer:"24y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"32×3/4 yは、まず32を4で割ってから3をかけると計算が楽になるよ。32÷4を計算してみよう。",next:"n2"},{id:"n2",type:"check",question:"32÷4の計算結果は？",choices:["8","6"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"32÷4は、4×8=32だから8になるよ。九九で確認してみよう。",next:"n2"},{id:"n3",type:"check",question:"8に分子の3をかけると？",choices:["23（暗算でずれた）","24（正しく計算した）"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"8×3は8を3回たす、8+8+8=24になるよ。落ち着いて計算しよう。",next:"n3"},{id:"n4",type:"explain",text:"32×3/4=24に文字yをつけて24yが答えだね。",next:"end"}]}},{id:"P0-MOJI-009",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-4/7 a)×(-21)",answer:"12a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-4/7 a)×(-21)は、まず数どうしの計算をするよ。21と分母7で約分できそうだね。",next:"n2"},{id:"n2",type:"check",question:"21÷7の計算結果は？",choices:["3","84（約分せず分子だけかけた）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数のかけ算では、先に約分すると計算が簡単になるよ。21と7を約分すると21÷7=3だね。",next:"n2"},{id:"n3",type:"check",question:"負の数×負の数の符号はどうなる？",choices:["マイナスが1個残る","正になる"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"マイナスは2個あると打ち消し合って正になるよ。「マイナスが1個残る」は誤りだよ。",next:"n3"},{id:"n4",type:"explain",text:"3×4=12、符号は正だから12。文字aをつけて12aが答えだね。",next:"end"}]}},{id:"P0-MOJI-010",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-0.5)×14x",answer:"-7x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-0.5)×14xは、数どうし(-0.5)と14をかけるよ。0.5をかけることは「半分にする」ことと同じだよ。",next:"n2"},{id:"n2",type:"check",question:"14の半分はいくつ？",choices:["9","7"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"14を2つに分けると7と7になるね。14の半分は7だよ。",next:"n2"},{id:"n3",type:"check",question:"負の数×正の数の符号はどうなる？",choices:["負になる","正のまま"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"負×正は負になるよ。7にマイナスをつけて-7にしよう。",next:"n3"},{id:"n4",type:"explain",text:"(-0.5)×14=-7に文字xをつけて-7xが答えだね。",next:"end"}]}},{id:"P0-MOJI-011",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"18b÷6",answer:"3b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"18b÷6は、数どうしの18と6で割り算をして、文字bはそのまま残すよ。",next:"n2"},{id:"n2",type:"check",question:"÷6という記号は、答えを書くときにどう扱う？",choices:["記号だけ消して18bのままにする","18÷6の計算を実際に行う"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は「割る」という意味の計算そのものだから、記号を消すだけではダメだよ。実際に18÷6を計算する必要があるよ。",next:"n2"},{id:"n3",type:"check",question:"18÷6の計算結果は？",choices:["3","6"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"6×3=18だから、18÷6=3だよ。九九の逆から考えてみよう。",next:"n3"},{id:"n4",type:"explain",text:"18÷6=3に文字bをつけて3bが答えだね。",next:"end"}]}},{id:"P0-MOJI-012",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"7/4 y÷(-14)",answer:"-1/8 y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"分数のわり算は、わる数の逆数をかけ算に直して計算するよ。÷(-14)は×(-1/14)になるんだ。",next:"n2"},{id:"n2",type:"check",question:"÷(-14)を逆数のかけ算に直すとどうなる？",choices:["そのまま14を分数の下に並べる","×(-1/14)に直す"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷の記号を消すだけでは計算になっていないよ。わる数の逆数をかける、という手順が必要だよ。",next:"n2"},{id:"n3",type:"explain",text:"7/4×(-1/14)を計算しよう。分子の7と分母の14は約分できるね。",next:"n4"},{id:"n4",type:"check",question:"7/4×(-1/14)を約分して計算した結果、符号はどうなる？",choices:["正のまま1/8","負の-1/8"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"正の数÷負の数だから、符号は負になるよ。約分の計算に気を取られて符号を忘れないようにしよう。",next:"n4"},{id:"n5",type:"explain",text:"7/4÷(-14)=-1/8に文字yをつけて-1/8 yが答えだね。",next:"end"}]}},{id:"P0-MOJI-013",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-15b)÷3",answer:"-5b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-15b)÷3は、数どうしの-15と3で割り算をして、文字bはそのまま残すよ。",next:"n2"},{id:"n2",type:"check",question:"÷3という記号は、答えを書くときにどう扱う？",choices:["記号だけ消して-15bのままにする","-15÷3の計算を実際に行う"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は割り算そのものだから、記号を消すだけではダメだよ。実際に-15÷3を計算しよう。",next:"n2"},{id:"n3",type:"check",question:"負の数÷正の数の符号はどうなる？",choices:["負になる","正になる"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"負÷正は負になるよ。15÷3=5にマイナスをつけて-5にしよう。",next:"n3"},{id:"n4",type:"explain",text:"-15÷3=-5に文字bをつけて-5bが答えだね。",next:"end"}]}},{id:"P0-MOJI-014",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"36y÷(-9)",answer:"-4y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"36y÷(-9)は、数どうしの36と-9で割り算をして、文字yはそのまま残すよ。",next:"n2"},{id:"n2",type:"check",question:"÷(-9)という記号は、答えを書くときにどう扱う？",choices:["記号だけ消して36yのままにする","36÷(-9)の計算を実際に行う"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は割り算そのものだから、記号を消すだけではダメだよ。実際に36÷(-9)を計算しよう。",next:"n2"},{id:"n3",type:"check",question:"正の数÷負の数の符号はどうなる？",choices:["正のまま","負になる"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"正÷負は負になるよ。36÷9=4にマイナスをつけて-4にしよう。",next:"n3"},{id:"n4",type:"explain",text:"36÷(-9)=-4に文字yをつけて-4yが答えだね。",next:"end"}]}},{id:"P0-MOJI-015",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-24x)÷(-8)",answer:"3x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-24x)÷(-8)は、数どうしの-24と-8で割り算をして、文字xはそのまま残すよ。",next:"n2"},{id:"n2",type:"check",question:"÷(-8)という記号は、答えを書くときにどう扱う？",choices:["記号だけ消して-24xのままにする","-24÷(-8)の計算を実際に行う"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は割り算そのものだから、記号を消すだけではダメだよ。実際に-24÷(-8)を計算しよう。",next:"n2"},{id:"n3",type:"check",question:"負の数÷負の数の符号はどうなる？",choices:["マイナスが1個残る","正になる"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"マイナスは2個あると打ち消し合って正になるよ。「1個残る」は誤りだよ。負÷負＝正、と覚えよう。",next:"n3"},{id:"n4",type:"explain",text:"24÷8=3、符号は正だから3。文字xをつけて3xが答えだね。",next:"end"}]}},{id:"P0-MOJI-016",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"6a÷(-1)",answer:"-6a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"6a÷(-1)は、数どうしの6と-1で割り算をして、文字aはそのまま残すよ。÷(-1)は「変化なし」に見えるけど注意しよう。",next:"n2"},{id:"n2",type:"check",question:"÷(-1)という記号は答えを書くときにどう扱う？",choices:["記号だけ消して6aのままにする","6÷(-1)の計算を実際に行う"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は割り算そのものだから、記号を消すだけではダメだよ。1で割るときも、符号まで含めてちゃんと計算しよう。",next:"n2"},{id:"n3",type:"check",question:"6÷(-1)の計算結果は？",choices:["6のまま変化しない","-6（符号が反転する）"],correct:1,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"1で割ると数の大きさは変わらないけど、割る数が負だから符号は反転するよ。6÷(-1)=-6になるんだ。",next:"n3"},{id:"n4",type:"explain",text:"6÷(-1)=-6に文字aをつけて-6aが答えだね。",next:"end"}]}},{id:"P0-MOJI-017",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-32b)÷(-4)",answer:"8b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"負の数どうしの割り算を考えます。(-32b)÷(-4) のように、マイナスが2つ出てくると符号でこんがらがりやすいので、まず符号だけを先に決める練習をしましょう。",next:"n2"},{id:"n2",type:"check",question:"負÷負の符号は、正と負のどちらになる？",choices:["正になる","負になる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"負の数どうしの割り算では、符号は必ず正になります。マイナスが2つあるとつい『マイナスが残る』と思ってしまいますが、負÷負→正、というルールを先に確定させましょう。",next:"n2"},{id:"n3",type:"explain",text:"符号が正だとわかったら、あとは数字部分の計算です。32÷4=8。この8に文字bをつければ答えが完成します。",next:"n4"},{id:"n4",type:"check",question:"(-32b)÷(-4) の答えとして正しいのはどれ？",choices:["8b","-8b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号は負÷負で正だったので、-8bのようにマイナスを残してはいけません。数の計算32÷4=8に文字bをつけた8bが正解です。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：負の数どうしの割り算は、①符号を先に決める（負÷負→正）、②数字だけを計算する、③文字をつける、の順で進めると符号ミスを防げます。",next:"end"}]}},{id:"P0-MOJI-018",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"5y÷1/3",answer:"15y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"分数でわる計算を考えます。5y÷1/3 のように÷のあとが分数のとき、÷の記号をそのまま分数の線に置き換えるだけでは計算が終わりません。",next:"n2"},{id:"n2",type:"check",question:"分数でわる計算は、どんな形に直してから計算する？",choices:["わる数の逆数をかける形","そのまま分数の線にするだけ"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷を分数の線にするだけでは不十分です。分数でわるときは『わる数をひっくり返して（逆数にして）かける』という操作が必要です。1/3の逆数は3です。",next:"n2"},{id:"n3",type:"explain",text:"5y÷1/3 は、1/3の逆数3をかけて 5y×3 に直せます。あとは5×3=15を計算し、文字yをつければ答えです。",next:"n4"},{id:"n4",type:"check",question:"5y÷1/3 の答えとして正しいのはどれ？",choices:["15y","5y/3"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5y/3は÷をそのまま分数の線にしただけで、逆数をかける操作ができていません。5y×3=15yが正解です。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：分数でわるときは、①わる数の逆数をかける形に直す、②数字を計算する、③文字をつける、の順で進めましょう。",next:"end"}]}},{id:"P0-MOJI-019",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"15b÷(-3/5)",answer:"-25b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"正の数を負の分数でわる計算を考えます。15b÷(-3/5) のように符号と分数が同時に出てくると、符号を忘れたり逆数の操作を忘れたりしやすくなります。",next:"n2"},{id:"n2",type:"check",question:"正÷負の商の符号は？",choices:["負になる","正になる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"正の数を負の数でわると、商は必ず負になります。15b÷(-3/5)では、符号は負と先に決めておきましょう。",next:"n2"},{id:"n3",type:"check",question:"-3/5でわる計算は、どんな形に直す？",choices:["逆数の5/3をかける形","そのまま分数の線にするだけ"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"分数でわるときは、わる数をひっくり返して（逆数にして）かける形に直します。-3/5の逆数は-5/3、符号は別に決めているので数の部分は5/3を使います。",next:"n3"},{id:"n4",type:"explain",text:"符号(負)と数の計算15×5/3=25を合わせると、答えは-25bになります。符号を忘れる、逆数にし忘れる、の2つのミスに気をつけましょう。",next:"n5"},{id:"n5",type:"explain",text:"まとめ：分数でわる計算は、①符号を先に決める、②逆数をかける形に直す、③数字を計算する、④符号と文字をつけて仕上げる、の順で進めましょう。",next:"end"}]}},{id:"P0-MOJI-020",subunit:"一次式と数の乗除",difficulty:"★1基礎",problem_text:"(-8/3 y)÷4/3",answer:"-2y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"負の分数係数を正の分数でわる計算を考えます。(-8/3 y)÷4/3 のように分数どうしの計算では、約分と符号の両方に気をつける必要があります。",next:"n2"},{id:"n2",type:"check",question:"負÷正の商の符号は？",choices:["負になる","正になる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"負の数を正の数でわると、商は必ず負になります。先に符号を負と決めておきましょう。",next:"n2"},{id:"n3",type:"explain",text:"4/3でわる計算は、逆数3/4をかける形に直します。-8/3×3/4を計算するとき、8と4を4で約分、3と3を約分すると、数の部分は2になります。",next:"n4"},{id:"n4",type:"check",question:"(-8/3 y)÷4/3 の答えとして正しいのはどれ？",choices:["-2y","2y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"数の計算2は合っていても、負÷正で符号は負になるはずです。符号を忘れずにつけた-2yが正解です。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：分数どうしの割り算は、①符号を先に決める、②逆数をかける形に直す、③かける前に約分する、④符号をつけて仕上げる、の順で進めましょう。",next:"end"}]}},{id:"P0-MOJI-021",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"3y+(8y-5)",answer:"11y-5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"かっこのある式の計算を考えます。3y+(8y-5) のように、+のかっこはそのまま外せますが、外したあとに同類項をどこまでまとめるかがポイントです。",next:"n2"},{id:"n2",type:"check",question:"3yと8yと-5の3つの項のうち、同類項どうしでまとめられるのはどれとどれ？",choices:["3yと8y","3yと8yと-5の全部"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字yがついた3yと8yは同類項なのでまとめられますが、-5は文字がついていない定数項なので別物です。りんご3個とみかん2個を『5個』とまとめて言えないのと同じです。",next:"n2"},{id:"n3",type:"explain",text:"3y+8y=11yとまとめ、-5はそのまま残します。答えは11y-5です。",next:"n4"},{id:"n4",type:"check",question:"3y+(8y-5) の答えとして正しいのはどれ？",choices:["11y-5","6y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"6yは-5まで文字の係数として足してしまった誤りです。-5は定数項なので、11yとは別に残す必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：かっこを外したあとは、文字がついた項どうし・定数項どうしを見分けて、同類項だけをまとめましょう。",next:"end"}]}},{id:"P0-MOJI-022",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(-3y+9)+7y",answer:"4y+9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"かっこが先頭にくる式の計算を考えます。(-3y+9)+7y のように、かっこの前が+ならそのまま外せますが、定数項と文字項を混ぜないことが大切です。",next:"n2"},{id:"n2",type:"check",question:"-3y、9、7yのうち、同類項どうしでまとめられるのはどれとどれ？",choices:["-3yと7y","-3yと9と7yの全部"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字yがついた-3yと7yは同類項ですが、9は文字がついていない定数項なので別物です。3つを一緒に足してはいけません。",next:"n2"},{id:"n3",type:"explain",text:"-3y+7y=4yとまとめ、9はそのまま残します。答えは4y+9です。",next:"n4"},{id:"n4",type:"check",question:"(-3y+9)+7y の答えとして正しいのはどれ？",choices:["4y+9","13y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"13yは-3、9、7を全部文字の係数として足してしまった誤りです。9は定数項なので、4yとは別に残す必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：かっこの位置が変わっても、文字項と定数項を見分けて、同類項だけをまとめる手順は同じです。",next:"end"}]}},{id:"P0-MOJI-023",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(5b-9)+(-4b-6)",answer:"b-15",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2つのかっこを+でつなぐ式の計算を考えます。(5b-9)+(-4b-6) のように項が4つあると、文字項と定数項を混ぜてしまいやすくなります。",next:"n2"},{id:"n2",type:"check",question:"5b、-9、-4b、-6のうち、同類項どうしの組はどれ？",choices:["5bと-4b、-9と-6の2組","4つ全部が1つの同類項"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字bがついた5bと-4bが1組、数字だけの-9と-6がもう1組です。4つを全部まとめて1つの数字にしてはいけません。",next:"n2"},{id:"n3",type:"explain",text:"5b-4b=b、-9-6=-15と、それぞれ別々に計算します。答えはb-15です。",next:"n4"},{id:"n4",type:"check",question:"(5b-9)+(-4b-6) の答えとして正しいのはどれ？",choices:["b-15","-14b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-14bは5、-9、-4、-6を全部文字の係数として足してしまった誤りです。文字項と定数項は分けて計算しましょう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：項が4つあっても、文字項どうし・定数項どうしのペアを見分けて、それぞれ別々にまとめれば大丈夫です。",next:"end"}]}},{id:"P0-MOJI-024",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(-7y+3)+(-6+y)",answer:"-6y-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"定数項が先にくる項を含む式を考えます。(-7y+3)+(-6+y) のように項の順番がバラバラだと、同類項を見つけにくくなります。",next:"n2"},{id:"n2",type:"check",question:"-7y、3、-6、yのうち、同類項どうしの組はどれ？",choices:["-7yとy、3と-6の2組","4つ全部が1つの同類項"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"順番が違っても、文字yがついた-7yとyが1組、数字だけの3と-6がもう1組です。並び順ではなく文字の有無で見分けましょう。",next:"n2"},{id:"n3",type:"explain",text:"-7y+y=-6y、3-6=-3と、それぞれ別々に計算します。答えは-6y-3です。",next:"n4"},{id:"n4",type:"check",question:"(-7y+3)+(-6+y) の答えとして正しいのはどれ？",choices:["-6y-3","-9y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-9yは-7、3、-6、1を全部文字の係数として足してしまった誤りです。定数項と文字項は分けて計算しましょう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：項の並び順が変わっても、文字がついているかどうかだけで同類項を見分ければ、計算の手順は同じです。",next:"end"}]}},{id:"P0-MOJI-025",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(9-5y)+(5y+4)",answer:"13",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字の項どうしが打ち消し合う式を考えます。(9-5y)+(5y+4) のように-5yと5yが両方あると、足すと0になり文字が消えることがあります。",next:"n2"},{id:"n2",type:"check",question:"-5yと5yを足すと係数はどうなる？",choices:["0になり、文字ごと消える","-10yになる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-5+5=0なので、-5yと5yを足すと0y、つまり文字ごと消えます。同じ文字どうしを足すか引くかは、係数の符号を見て決めます。",next:"n2"},{id:"n3",type:"explain",text:"文字の項が消えたので、残るのは定数項の9と4です。9+4=13となり、答えは文字のない13です。",next:"n4"},{id:"n4",type:"check",question:"(9-5y)+(5y+4) の答えとして正しいのはどれ？",choices:["13","13y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"答えに文字が残らないのは変なことではありません。-5yと5yが打ち消し合って0になった結果なので、13yと文字をつける必要はありません。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：文字の項どうしを足したとき係数が0になれば、その文字は答えに残りません。違和感があっても無理に文字をつけないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-026",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(4b-6)+(8-8b)",answer:"-4b+2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字の項が打ち消し合わずに残る式を考えます。(4b-6)+(8-8b) のように係数の絶対値が違うと、0にはならず符号つきで文字が残ります。",next:"n2"},{id:"n2",type:"check",question:"4bと-8bを足すと、係数はどうなる？",choices:["-4bになる（打ち消し合わない）","0になり文字が消える"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"4と-8は絶対値が違うので打ち消し合いません。4-8=-4を計算すると、-4bとして文字が残ります。0だと思い込まないよう、必ず計算で確かめましょう。",next:"n2"},{id:"n3",type:"explain",text:"定数項は-6+8=2です。文字項-4bと定数項2を合わせて、答えは-4b+2になります。",next:"n4"},{id:"n4",type:"check",question:"(4b-6)+(8-8b) の答えとして正しいのはどれ？",choices:["-4b+2","-4b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-4bだけでは不十分です。-6+8=2という定数項の計算を忘れずに、-4b+2まで書きましょう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：同類項をまとめるときは、打ち消し合うと思い込まず、係数の計算を最後まで正確に行いましょう。",next:"end"}]}},{id:"P0-MOJI-027",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"8b-(3b+6)",answer:"5b-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"かっこの前がマイナスの減法を考えます。8b-(3b+6) のように-のかっこがあるとき、符号がどこまで変わるかが重要なポイントです。",next:"n2"},{id:"n2",type:"check",question:"かっこの前の-は、かっこの中のどの項に効く？",choices:["中の全部の項","最初の項だけ"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、中の全部の項の符号を変えます。3bだけでなく6の符号も変えて、-3b、-6にする必要があります。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると8b-3b-6になります。8bと-3bをまとめて5b、-6はそのまま残り、答えは5b-6です。",next:"n4"},{id:"n4",type:"check",question:"8b-(3b+6) の答えとして正しいのはどれ？",choices:["5b-6","5b+6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5b+6は6の符号を変え忘れた誤りです。かっこの前の-は6にも効くので、-6として計算する必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：かっこの前が-のときは、中の全部の項の符号を変えてから外しましょう。最初の項だけと思い込まないことが大切です。",next:"end"}]}},{id:"P0-MOJI-028",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(5y-3)-(8y-4)",answer:"-3y+1",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"かっこの中に負の項がある減法を考えます。(5y-3)-(8y-4) のように2番目のかっこの中に-4があると、符号反転を忘れやすくなります。",next:"n2"},{id:"n2",type:"check",question:"-(8y-4) を外すとき、-4はどうなる？",choices:["+4になる","-4のまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、8yだけでなく-4にも効きます。-4の符号を変えると+4になります。かっこの中の負の項も忘れずに符号を変えましょう。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると5y-3-8y+4になります。5y-8y=-3y、-3+4=1とまとめると、答えは-3y+1です。",next:"n4"},{id:"n4",type:"check",question:"(5y-3)-(8y-4) の答えとして正しいのはどれ？",choices:["-3y+1","-3y-7"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-3y-7は-4の符号を変え忘れた誤りです。-(8y-4)は-8y+4になるので、+4として定数項を計算する必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：かっこの中に負の項があっても、-のかっこを外すときは全部の項の符号を変えるルールは同じです。",next:"end"}]}},{id:"P0-MOJI-029",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(6y+5)-(4y-3)",answer:"2y+8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"ひく式の中に負の項がある減法を考えます。(6y+5)-(4y-3) のように-3を引くと、符号が変わって定数項が増えることがあります。",next:"n2"},{id:"n2",type:"check",question:"-(4y-3) を外すとき、-3はどうなる？",choices:["+3になる","-3のまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、4yだけでなく-3にも効きます。-3の符号を変えると+3になります。マイナスをひくとプラスになる、という感覚をつかみましょう。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると6y+5-4y+3になります。6y-4y=2y、5+3=8とまとめると、答えは2y+8です。",next:"n4"},{id:"n4",type:"check",question:"(6y+5)-(4y-3) の答えとして正しいのはどれ？",choices:["2y+8","2y+2"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2y+2は-3の符号を変え忘れた誤りです。-(4y-3)は-4y+3になるので、+3として定数項を計算する必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：ひく式の中に負の項があるときは、符号反転でプラスに変わることを見落とさないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-030",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(3b-6)-(5b+2)",answer:"-2b-8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"ひいた結果、文字項の符号が負に変わる減法を考えます。(3b-6)-(5b+2) のように、ひく数の係数の方が大きいと結果は負の係数になります。",next:"n2"},{id:"n2",type:"check",question:"-(5b+2) を外すとき、5bと2はそれぞれどうなる？",choices:["両方符号が変わり-5bと-2になる","5bだけ符号が変わり2はそのまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、5bと2の両方に効きます。5bは-5bに、2は-2に、どちらも符号を変える必要があります。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると3b-6-5b-2になります。3b-5b=-2b、-6-2=-8とまとめると、答えは-2b-8です。",next:"n4"},{id:"n4",type:"check",question:"(3b-6)-(5b+2) の答えとして正しいのはどれ？",choices:["-2b-8","-2b-4"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-2b-4は定数項の計算-6-2を誤ったか、2の符号反転を忘れた誤りです。-6-2は-8になります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：ひく数の係数が大きいと文字項がマイナスになることもあります。符号変化と計算を最後まで丁寧に行いましょう。",next:"end"}]}},{id:"P0-MOJI-031",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(4b-8)-(-b+5)",answer:"5b-13",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"ひく式の最初の項が負である減法を考えます。(4b-8)-(-b+5) のように-bのようなマイナスの項をひくと、符号の変化が分かりにくくなります。",next:"n2"},{id:"n2",type:"check",question:"-(-b+5) を外すとき、-bはどうなる？",choices:["+bになる","-bのまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、-bにも効きます。マイナスの符号を変えるとプラスbになります。マイナスが2つ重なると混乱しやすいですが、1つずつ確実に変えましょう。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると4b-8+b-5になります。4b+b=5b、-8-5=-13とまとめると、答えは5b-13です。",next:"n4"},{id:"n4",type:"check",question:"(4b-8)-(-b+5) の答えとして正しいのはどれ？",choices:["5b-13","5b-3"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5b-3は5の符号反転を忘れた誤りです。-(-b+5)の5は-5になるので、-8-5=-13として定数項を計算する必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：ひく式の最初の項が負でも、かっこの前の-は中の全部の項に効くというルールは変わりません。1項ずつ確実に符号を変えましょう。",next:"end"}]}},{id:"P0-MOJI-032",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(-6+5y)-(-3y-7)",answer:"8y+1",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"ひく式の中の項が両方とも負である減法を考えます。(-6+5y)-(-3y-7) のように-3yと-7がどちらもマイナスだと、符号変化がさらに分かりにくくなります。",next:"n2"},{id:"n2",type:"check",question:"-(-3y-7) を外すとき、-3yと-7はそれぞれどうなる？",choices:["両方符号が変わり+3yと+7になる","最初の-3yだけ符号が変わる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の-は、-3yと-7の両方に効きます。どちらもマイナスをひくのでプラスに変わり、+3yと+7になります。最初の項だけと思い込まないようにしましょう。",next:"n2"},{id:"n3",type:"explain",text:"符号を変えると-6+5y+3y+7になります。5y+3y=8y、-6+7=1とまとめると、答えは8y+1です。",next:"n4"},{id:"n4",type:"check",question:"(-6+5y)-(-3y-7) の答えとして正しいのはどれ？",choices:["8y+1","8y-13"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"8y-13は-7の符号反転を忘れた誤りです。-(-3y-7)の-7は+7になるので、-6+7=1として定数項を計算する必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：かっこの中がどちらもマイナスの項でも、-のかっこを外すときは全部の項の符号を変えるルールは変わりません。落ち着いて1項ずつ確認しましょう。",next:"end"}]}},{id:"P0-MOJI-033",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(6b+2)+(3b-4)",answer:"9b-2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(6b+2)+(3b-4)を計算します。かっこの前が「+」のときは、かっこの中の符号をそのままにして外すことができます。",next:"n2"},{id:"n2",type:"check",question:"かっこを外すと、6b+2+3b-4になります。この式のbの項をすべて集めるとどうなりますか？",choices:["6b+3b=9b","6b-3b=3b"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前が+なので符号はそのままです。6bと3bはどちらも+の符号がついているので、そのまま足して9bになります。",next:"n2"},{id:"n3",type:"check",question:"次に数の項2と-4をまとめます。符号を含めて正しく計算するとどれですか？",choices:["2-4=-2","2+4=6"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-4の「-」は符号なので、4だけを取り出して2と足してはいけません。2に-4を加えると2-4=-2です。符号を忘れずに計算しましょう。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：9bと-2を合わせて、答えは9b-2です。かっこを外すときの符号と、数の項の符号をセットで考えることが大切です。",next:"end"}]}},{id:"P0-MOJI-034",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(3y-4)+(-5y+7)",answer:"-2y+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3y-4)+(-5y+7)を計算します。かっこの前が+なので、符号はそのままで外せます。3y-4-5y+7になります。",next:"n2"},{id:"n2",type:"check",question:"yの項3yと-5yをまとめると、どちらが正しいですか？",choices:["3y-5y=-2y","3y-5y=2y"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"3yと-5yは係数3と-5を足すと考えます。3+(-5)=-2なので、答えは-2yです。符号を先に決めてから絶対値を計算しないようにしましょう。",next:"n2"},{id:"n3",type:"check",question:"数の項-4と7をまとめると、どちらが正しいですか？",choices:["-4+7=3","-4+7=-11"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"7の前は+の符号（かっこを外す前は+7）です。-4に+7を足すので-4+7=3です。7を独立した数として引いてはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：-2yと3を合わせて、答えは-2y+3です。",next:"end"}]}},{id:"P0-MOJI-035",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(y-6)+(8-3y)",answer:"-2y+2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(y-6)+(8-3y)を計算します。かっこの前が+なので符号はそのままで外せます。y-6+8-3yになります。",next:"n2"},{id:"n2",type:"check",question:"yの項はyと-3yです。まとめるとどちらが正しいですか？",choices:["y-3y=-2y","y-3y=y（打ち消し合う）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"yと-3yは同じ文字なので同類項ですが、係数が1と-3で異なるので打ち消し合いません。1+(-3)=-2なので-2yになります。",next:"n2"},{id:"n3",type:"check",question:"数の項-6と8をまとめると、どちらが正しいですか？",choices:["-6+8=2","-6+8=-14"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-6に8を足すので-6+8=2です。符号を確認しながら数直線をイメージして計算しましょう。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：-2yと2を合わせて、答えは-2y+2です。",next:"end"}]}},{id:"P0-MOJI-036",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(7b-4)-(3b+5)",answer:"4b-9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(7b-4)-(3b+5)を計算します。ひくかっこの前は-なので、かっこの中のすべての符号を反転してから外します。",next:"n2"},{id:"n2",type:"check",question:"(3b+5)の符号をすべて反転すると、どちらが正しいですか？",choices:["-3b-5","-3b+5"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号の反転は最初の項だけでなく、かっこの中の全部の項に対して行います。3b→-3b、+5→-5です。",next:"n2"},{id:"n3",type:"check",question:"7b-4-3b-5となったら、bの項どうしをまとめるとどちらが正しいですか？",choices:["7b-3b=4b","7b+3b=10b"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-3bは符号込みで「マイナス3b」です。7bから3bをひくので7b-3b=4bになります。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：4bと数の項-4-5=-9を合わせて、答えは4b-9です。",next:"end"}]}},{id:"P0-MOJI-037",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(6b+2)-(-3b+7)",answer:"9b-5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(6b+2)-(-3b+7)を計算します。ひくかっこの前は-なので、中の符号をすべて反転してから外します。",next:"n2"},{id:"n2",type:"check",question:"(-3b+7)の符号をすべて反転すると、どちらが正しいですか？",choices:["+3b-7","-3b-7"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-3b→+3b、+7→-7と、両方の項の符号を変えます。最初の項だけではありません。",next:"n2"},{id:"n3",type:"check",question:"数の項2と-7をまとめると、どちらが正しいですか？",choices:["2-7=-5","2-7=9"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"2に-7を足すので2-7=-5です。符号なしの「7」として扱うと間違えます。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：9bと-5を合わせて、答えは9b-5です。",next:"end"}]}},{id:"P0-MOJI-038",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(-6+y)-(-6-5y)",answer:"6y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-6+y)-(-6-5y)を計算します。ひくかっこの前は-なので、中の符号をすべて反転してから外します。",next:"n2"},{id:"n2",type:"check",question:"(-6-5y)の符号をすべて反転すると、どちらが正しいですか？",choices:["+6+5y","-6+5y"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-6→+6、-5y→+5yと、両方の項の符号を変えます。最初の項だけを反転してはいけません。",next:"n2"},{id:"n3",type:"check",question:"-6+y+6+5yの数の項-6と6をまとめると、どちらが正しいですか？",choices:["-6+6=0","-6+6=-12"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-6に6を足すと打ち消し合って0になります。符号を無視して絶対値どうしを足してはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：数の項が0で消え、yの項y+5y=6yだけが残ります。答えは6yです。",next:"end"}]}},{id:"P0-MOJI-039",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"y+9 と 3y-4 をたしなさい。",answer:"4y+5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「y+9 と 3y-4 をたす」ので、2つの式をかっこでつないで(y+9)+(3y-4)とします。かっこの前は+です。",next:"n2"},{id:"n2",type:"check",question:"かっこを外すと、y+9+3y-4になります。これは「たし算」の式ですか、「ひき算」の式ですか？",choices:["たし算（かっこの前が+）","ひき算（-4が出てきたから）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"式の中に-4という数があっても、2つの式全体を「たす」ことに変わりはありません。かっこの前が+なので符号はそのままです。",next:"n2"},{id:"n3",type:"check",question:"数の項9と-4をまとめると、どちらが正しいですか？",choices:["9-4=5","9+4=13"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-4の「-」は符号なので、9に-4を足すと9-4=5です。符号を無視して9と4を足してはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：yの項4yと数の項5を合わせて、答えは4y+5です。",next:"end"}]}},{id:"P0-MOJI-040",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"4y+3 と 2y-3 をたしなさい。",answer:"6y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「4y+3 と 2y-3 をたす」ので、2つの式をかっこでつないで(4y+3)+(2y-3)とします。かっこの前は+です。",next:"n2"},{id:"n2",type:"check",question:"かっこを外すと4y+3+2y-3になります。数の項3と-3をまとめるとどちらが正しいですか？",choices:["3-3=0","3+3=6"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-3の「-」は符号です。3に-3を足すと3-3=0で打ち消し合います。符号を無視して3と3を足してはいけません。",next:"n2"},{id:"n3",type:"check",question:"yの項4yと2yをまとめると、どちらが正しいですか？",choices:["4y+2y=6y","4y+2y=6"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"4yと2yは同類項なので、係数だけ足して文字yはそのまま残ります。4+2=6でyがつくので6yです。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：数の項は打ち消し合って0、yの項は6yだけが残ります。答えは6yです。",next:"end"}]}},{id:"P0-MOJI-041",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"8y+9 から 5y+4 をひきなさい。",answer:"3y+5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「8y+9 から 5y+4 をひく」は、「Aから Bをひく」＝A-Bという意味です。(8y+9)-(5y+4)と立式します。",next:"n2"},{id:"n2",type:"check",question:"この式の立て方として正しいのはどちらですか？",choices:["(8y+9)-(5y+4)","(5y+4)-(8y+9)"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「AからBをひく」は必ずA-Bの順です。「8y+9から」なので8y+9が先、「5y+4をひく」ので5y+4を後ろでひきます。",next:"n2"},{id:"n3",type:"check",question:"ひくかっこの符号を全部反転して8y+9-5y-4としたとき、数の項9と-4をまとめるとどちらが正しいですか？",choices:["9-4=5","9+4=13"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-4の「-」は符号なので、9に-4を足すと9-4=5です。符号を無視して9と4を足してはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：yの項3yと数の項5を合わせて、答えは3y+5です。",next:"end"}]}},{id:"P0-MOJI-042",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"-4y-6 から 7y+3 をひきなさい。",answer:"-11y-9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「-4y-6 から 7y+3 をひく」は、「Aから Bをひく」＝A-Bという意味です。(-4y-6)-(7y+3)と立式します。",next:"n2"},{id:"n2",type:"check",question:"この式の立て方として正しいのはどちらですか？",choices:["(-4y-6)-(7y+3)","(7y+3)-(-4y-6)"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「AからBをひく」は必ずA-Bの順です。「-4y-6から」なので-4y-6が先、「7y+3をひく」ので7y+3を後ろでひきます。",next:"n2"},{id:"n3",type:"check",question:"ひくかっこの符号を全部反転して-4y-6-7y-3としたとき、数の項-6と-3をまとめるとどちらが正しいですか？",choices:["-6-3=-9","-6-3=-3"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-6に-3を足すので-6-3=-9です。符号を後付けにして-6+3=-3のように計算してはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：yの項-11yと数の項-9を合わせて、答えは-11y-9です。",next:"end"}]}},{id:"P0-MOJI-043",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"5y+(4y-3)",answer:"9y-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5y+(4y-3)を計算します。かっこの前が+なので、符号はそのままで外せます。5y+4y-3になります。",next:"n2"},{id:"n2",type:"check",question:"yの項5yと4yをまとめるとき、正しい計算はどちらですか？",choices:["5y+4y=9y（係数を足す）","5y×4y=20y（係数をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"5yと4yは同類項なので、係数どうしをたし算します。かけ算ではありません。5+4=9でyがつくので9yです。",next:"n2"},{id:"n3",type:"check",question:"数の項-3はどのように答えに残りますか？",choices:["符号ごとそのまま-3として残る","符号が消えて+3になる"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-3の「-」は符号の一部です。他にまとめる数の項がないので、符号ごとそのまま-3として残します。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：9yと-3を合わせて、答えは9y-3です。",next:"end"}]}},{id:"P0-MOJI-044",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(3b-8)+(-6b+5)",answer:"-3b-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3b-8)+(-6b+5)を計算します。かっこの前が+なので、符号はそのままで外せます。3b-8-6b+5になります。",next:"n2"},{id:"n2",type:"check",question:"bの項3bと-6bをまとめると、どちらが正しいですか？",choices:["3b-6b=-3b","3b-6b=9b"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"3と-6を足すと3+(-6)=-3です。符号を取り違えて3+6=9のように計算しないようにしましょう。",next:"n2"},{id:"n3",type:"check",question:"数の項-8と5をまとめると、どちらが正しいですか？",choices:["-8+5=-3","-8+5=3"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-8に5を足すので-8+5=-3です。符号を無視して8と5の差を出し、プラスをつけてはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：-3bと-3を合わせて、答えは-3b-3です。",next:"end"}]}},{id:"P0-MOJI-045",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(6y+5)+(2y-3)",answer:"8y+2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(6y+5)+(2y-3)を計算します。かっこの前が+なので、符号はそのままで外せます。6y+5+2y-3になります。",next:"n2"},{id:"n2",type:"check",question:"yの項6yと2yをまとめると、どちらが正しいですか？",choices:["6y+2y=8y","6y+2y=6y-2y=4y"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"6yと2yはどちらも+の符号がついた同類項です。そのまま足して6+2=8でyがつくので8yです。",next:"n2"},{id:"n3",type:"check",question:"数の項5と-3をまとめると、どちらが正しいですか？",choices:["5-3=2","5+3=8"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-3の「-」は符号なので、5に-3を足すと5-3=2です。符号を無視して5と3を足してはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：8yと2を合わせて、答えは8y+2です。",next:"end"}]}},{id:"P0-MOJI-046",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(3b-6)+(-7b+2)",answer:"-4b-4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3b-6)+(-7b+2)を計算します。かっこの前が+なので、符号はそのままで外せます。3b-6-7b+2になります。",next:"n2"},{id:"n2",type:"check",question:"bの項3bと-7bをまとめると、どちらが正しいですか？",choices:["3b-7b=-4b","3b-7b=10b"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"3と-7を足すと3+(-7)=-4です。符号を取り違えて3+7=10のように計算しないようにしましょう。",next:"n2"},{id:"n3",type:"check",question:"数の項-6と2をまとめると、どちらが正しいですか？",choices:["-6+2=-4","-6+2=4"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-6に2を足すので-6+2=-4です。符号を無視して6と2の差を出し、プラスをつけてはいけません。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：-4bと-4を合わせて、答えは-4b-4です。",next:"end"}]}},{id:"P0-MOJI-047",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(8y+3)-7y",answer:"y+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(8y+3)-7yを計算します。かっこの前は+なので、そのまま外して8y+3-7yになります。",next:"n2"},{id:"n2",type:"check",question:"8yと-7yは同じ文字yの項です。これは同類項としてまとめられますか？",choices:["まとめられる（8y-7y=y）","まとめられない（別の項として残す）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"8yも-7yも文字yの項なので、同類項としてまとめることができます。符号があっても文字が同じなら同類項です。",next:"n2"},{id:"n3",type:"check",question:"8y-7yを計算すると、どちらが正しいですか？",choices:["8-7=1なのでy","8+7=15なので15y"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"-7yの「-」は符号です。8yから7yをひくので8-7=1、係数1は省略してyと書きます。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：yの項yと数の項3を合わせて、答えはy+3です。",next:"end"}]}},{id:"P0-MOJI-048",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"b-(-b+4)",answer:"2b-4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"b-(-b+4)を計算します。ひくかっこの前は-なので、中の符号をすべて反転してから外します。",next:"n2"},{id:"n2",type:"check",question:"(-b+4)の符号をすべて反転すると、どちらが正しいですか？",choices:["+b-4","+b+4"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-b→+b、+4→-4と、両方の項の符号を変えます。最初の項「-b」だけを反転して4はそのままにしてはいけません。",next:"n2"},{id:"n3",type:"check",question:"b+b-4のbの項をまとめると、どちらが正しいですか？",choices:["b+b=2b","b+b=0（打ち消し合う）"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"反転した後の式はb+b-4です。bと-bではなく、bとbなので打ち消し合いません。足して2bになります。",next:"n3"},{id:"n4",type:"explain",text:"まとめ：2bと-4を合わせて、答えは2b-4です。",next:"end"}]}},{id:"P0-MOJI-049",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(5x+4)-(6x-9)",answer:"-x+13",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(5x+4)-(6x-9)のように、かっこの前に「-」がついているとき、かっこの中の符号はどうなるか考えてみよう。",next:"n2"},{id:"n2",type:"check",question:"-(6x-9) のかっこを外すと、どうなるかな？",choices:["-6x-9","-6x+9","6x-9"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の「-」は、中のすべての項の符号を変えるはたらきをするよ。6xは-6xに、-9は+9に変わるから、-(6x-9)=-6x+9になるんだ。「-9」の「-」を引き算の記号だと思って符号を変え忘れる人が多いから気をつけよう。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。(5x+4)-(6x-9)=5x+4-6x+9になるよ。次は同類項をまとめよう。",next:"n4"},{id:"n4",type:"check",question:"5x+4-6x+9 を同類項ごとにまとめると？",choices:["-x+13","-x-13","x-13"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字の項どうし(5x-6x=-x)、数字どうし(4+9=13)をそれぞれ計算しよう。符号を最後にまとめて付け直さず、1つずつ計算するとミスが減るよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめると-x+13が正解だよ。ひくかっこは中の項すべての符号を変えることを忘れずに。",next:"end"}]}},{id:"P0-MOJI-050",subunit:"一次式の加法・減法",difficulty:"★2標準",problem_text:"(7b-3)-(2b+6)",answer:"5b-9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(7b-3)-(2b+6)のように、かっこの前に「-」がついているとき、かっこの中の符号はどうなるか考えてみよう。",next:"n2"},{id:"n2",type:"check",question:"-(2b+6) のかっこを外すと、どうなるかな？",choices:["-2b+6","-2b-6","2b+6"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの前の「-」は、中のすべての項の符号を変えるはたらきをするよ。2bは-2bに、+6は-6に変わるから、-(2b+6)=-2b-6になるんだ。「+6」は元々プラスの数字だから変えなくていい、と思い込む人が多いけど、符号のプラス・マイナスに関係なく全部変わるよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。(7b-3)-(2b+6)=7b-3-2b-6になるよ。次は同類項をまとめよう。",next:"n4"},{id:"n4",type:"check",question:"7b-3-2b-6 を同類項ごとにまとめると？",choices:["5b-9","5b+9","-5b-9"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字の項どうし(7b-2b=5b)、数字どうし(-3-6=-9)をそれぞれ計算しよう。符号を最後にまとめて付け直さず、1つずつ計算するとミスが減るよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめると5b-9が正解だよ。ひくかっこは中の項すべての符号を変えることを忘れずに。",next:"end"}]}},{id:"P0-MOJI-051",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"3(y+5)",answer:"3y+15",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3(y+5)のように、数とかっこのかけ算では、外の数をかっこの中のすべての項にかける「分配法則」を使うよ。",next:"n2"},{id:"n2",type:"check",question:"3は、かっこの中の何と何にかければいい？",choices:["yだけ","5だけ","yと5の両方"],correct:2,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。yだけにかけて5にかけ忘れると3y+5になってしまい、これは間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。3×y+3×5と考えるよ。計算すると3y+15になるね。",next:"n4"},{id:"n4",type:"check",question:"3yと15は、同類項としてまとめて1つの項にできる？",choices:["できる（18yにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"3yは文字yがついた項、15は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、3y+15がそのまま正解だよ。両方の項に外の数をかけて、種類の違う項はまとめないことがポイントだね。",next:"end"}]}},{id:"P0-MOJI-052",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"-5(3b-2)",answer:"-15b+10",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-5(3b-2)のように、外の数がマイナスのときも、かっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"-5は、かっこの中の何と何にかければいい？",choices:["3bだけ","3bと-2の両方","-2だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。3bだけにかけて-2にかけ忘れると-15b-2になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。-5×3b+(-5)×(-2)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"-5×(-2) の答えはどれ？",choices:["-10","+10"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-2の「-」は項自体の符号だから、引き算の記号だと思って無視してはいけないよ。負の数どうしをかけると答えはプラスになるから、-5×(-2)=+10だよ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-15b+10が正解だよ。項の符号をふくめて両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-053",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(4x-3)×7",answer:"28x-21",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(4x-3)×7のように、数がかっこの後ろにあっても、かっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"7は、かっこの中の何と何にかければいい？",choices:["4xだけ","-3だけ","4xと-3の両方"],correct:2,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。4xだけにかけて-3にかけ忘れると28x-3になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。4x×7+(-3)×7と考えるよ。計算すると28x-21になるね。",next:"n4"},{id:"n4",type:"check",question:"28xと-21は、同類項としてまとめて1つの項にできる？",choices:["できる（7xにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"28xは文字xがついた項、-21は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、28x-21がそのまま正解だよ。数の位置が前でも後ろでも両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-054",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(2y+5)×(-4)",answer:"-8y-20",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(2y+5)×(-4)のように、外の数がマイナスのときも、かっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"-4は、かっこの中の何と何にかければいい？",choices:["2yだけ","2yと5の両方","5だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。2yだけにかけて5にかけ忘れると-8y+5になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。2y×(-4)+5×(-4)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"5×(-4) の答えはどれ？",choices:["+20","-20"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5はもともとプラスの数字だけど、マイナスの-4をかけると符号はマイナスに変わるよ。正の数×負の数はマイナスになるという符号のルールを思い出そう。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-8y-20が正解だよ。項の符号がプラスでも、マイナスをかければ変わることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-055",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"1/3(6a-9)",answer:"2a-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"1/3(6a-9)のように、外の数が分数でも、かっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"1/3は、かっこの中の何と何にかければいい？",choices:["6aだけ","6aと-9の両方","-9だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は分数でも、かっこの中の項の数だけくり返しかける必要があるよ。6aだけにかけて-9にかけ忘れると2a-9になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。1/3×6a+1/3×(-9)と考えるよ。計算すると2a-3になるね。",next:"n4"},{id:"n4",type:"check",question:"2aと-3は、同類項としてまとめて1つの項にできる？",choices:["できる（-aにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2aは文字aがついた項、-3は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、2a-3がそのまま正解だよ。分数でも両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-056",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(2/3x+3/4)×(-12)",answer:"-8x-9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(2/3x+3/4)×(-12)のように、分母の違う分数がかっこの中にあっても、外の数をすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"-12は、かっこの中の何と何にかければいい？",choices:["2/3xだけ","2/3xと3/4の両方","3/4だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。2/3xだけにかけて3/4にかけ忘れると-8x+3/4になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。2/3x×(-12)+3/4×(-12)と考えるよ。それぞれ約分すると-8xと-9になるね。",next:"n4"},{id:"n4",type:"check",question:"3/4×(-12) の答えはどれ？",choices:["-9","+9"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"3/4×12=9で、-12だから符号はマイナスになるよ。2つの分数を続けて計算するときは、1つずつ符号を確認しながら進めよう。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-8x-9が正解だよ。両方の項に-12をかけて、符号も丁寧に確認することがポイントだね。",next:"end"}]}},{id:"P0-MOJI-057",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(10y+6)÷2",answer:"5y+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(10y+6)÷2のように、かっこを数で割るときも、かっこの中のすべての項をその数で割るよ。",next:"n2"},{id:"n2",type:"check",question:"2で割るのは、かっこの中の何と何？",choices:["10yだけ","6だけ","10yと6の両方"],correct:2,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"割り算も、かっこの中の項の数だけくり返し行う必要があるよ。10yだけ割って6を割り忘れると5y+6になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。10y÷2+6÷2と考えるよ。計算すると5y+3になるね。",next:"n4"},{id:"n4",type:"check",question:"5yと3は、同類項としてまとめて1つの項にできる？",choices:["できる（8yにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5yは文字yがついた項、3は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、5y+3がそのまま正解だよ。割り算でも両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-058",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(8x+12)÷(-4)",answer:"-2x-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(8x+12)÷(-4)のように、割る数がマイナスでも、かっこの中のすべての項をその数で割るよ。",next:"n2"},{id:"n2",type:"check",question:"-4で割るのは、かっこの中の何と何？",choices:["8xだけ","8xと12の両方","12だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"割り算も、かっこの中の項の数だけくり返し行う必要があるよ。8xだけ割って12を割り忘れると-2x+12になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。8x÷(-4)+12÷(-4)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"12÷(-4) の答えはどれ？",choices:["+3","-3"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"12はもともとプラスの数字だけど、マイナスの-4で割ると符号はマイナスに変わるよ。正の数÷負の数はマイナスになるという符号のルールを思い出そう。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-2x-3が正解だよ。項の符号がプラスでも、マイナスで割れば変わることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-059",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(9b-27)÷(-9)",answer:"-b+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(9b-27)÷(-9)のように、割る数がマイナスでも、かっこの中のすべての項をその数で割るよ。",next:"n2"},{id:"n2",type:"check",question:"-9で割るのは、かっこの中の何と何？",choices:["9bだけ","9bと-27の両方","-27だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"割り算も、かっこの中の項の数だけくり返し行う必要があるよ。9bだけ割って-27を割り忘れると-b-27になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。9b÷(-9)+(-27)÷(-9)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"(-27)÷(-9) の答えはどれ？",choices:["-3","+3"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-27の「-」は項自体の符号だから、引き算の記号だと思って無視してはいけないよ。負の数どうしを割ると答えはプラスになるから、(-27)÷(-9)=+3だよ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-b+3が正解だよ。項の符号をふくめて両方の項を割ることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-060",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(20-15y)÷(-5)",answer:"-4+3y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(20-15y)÷(-5)のように、定数項が先にあっても、かっこの中のすべての項を-5で割るよ。",next:"n2"},{id:"n2",type:"check",question:"-5で割るのは、かっこの中の何と何？",choices:["20だけ","20と-15yの両方","-15yだけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"割り算も、かっこの中の項の数だけくり返し行う必要があるよ。20だけ割って-15yを割り忘れると-4-15yになってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。20÷(-5)+(-15y)÷(-5)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"(-15y)÷(-5) の答えはどれ？",choices:["-3y","+3y"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-15yの「-」は項自体の符号だから、引き算の記号だと思って無視してはいけないよ。負の数どうしを割ると答えはプラスになるから、(-15y)÷(-5)=+3yだよ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-4+3yが正解だよ。項の順番に関係なく両方の項を割ることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-061",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(3a-2)÷1/4",answer:"12a-8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3a-2)÷1/4のように、分数で割るときは、その逆数をかけることに直せるよ。÷1/4は×4と同じだね。",next:"n2"},{id:"n2",type:"check",question:"×4に直したあと、4は、かっこの中の何と何にかければいい？",choices:["3aだけ","3aと-2の両方","-2だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"逆数をかける形に直しても、外の数はかっこの中の項の数だけくり返しかける必要があるよ。3aだけにかけて-2にかけ忘れると12a-2になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。3a×4+(-2)×4と考えるよ。計算すると12a-8になるね。",next:"n4"},{id:"n4",type:"check",question:"12aと-8は、同類項としてまとめて1つの項にできる？",choices:["できる（4aにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"12aは文字aがついた項、-8は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、12a-8がそのまま正解だよ。逆数のかけ算に直したあとも両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-062",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(3x+9)÷(-3/7)",answer:"-7x-21",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3x+9)÷(-3/7)のように、負の分数で割るときも、その逆数をかけることに直せるよ。÷(-3/7)は×(-7/3)と同じだね。",next:"n2"},{id:"n2",type:"check",question:"×(-7/3)に直したあと、-7/3は、かっこの中の何と何にかければいい？",choices:["3xだけ","3xと9の両方","9だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"逆数をかける形に直しても、外の数はかっこの中の項の数だけくり返しかける必要があるよ。3xだけにかけて9にかけ忘れると-7x+9になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。3x×(-7/3)+9×(-7/3)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"9×(-7/3) の答えはどれ？",choices:["+21","-21"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"9はもともとプラスの数字だけど、マイナスの-7/3をかけると符号はマイナスに変わるよ。正の数×負の数はマイナスになるという符号のルールを思い出そう。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-7x-21が正解だよ。逆数がマイナスなら、その符号もふくめて両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-063",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"5(3a+2)",answer:"15a+10",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5(3a+2)のように、数とかっこのかけ算では、外の数をかっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"5は、かっこの中の何と何にかければいい？",choices:["3aだけ","2だけ","3aと2の両方"],correct:2,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。3aだけにかけて2にかけ忘れると15a+2になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。5×3a+5×2と考えるよ。計算すると15a+10になるね。",next:"n4"},{id:"n4",type:"check",question:"15aと10は、同類項としてまとめて1つの項にできる？",choices:["できる（25aにする）","できない（文字の項と数字の項は別）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"15aは文字aがついた項、10は数字だけの項だよ。種類が違う項は足し合わせて1つの項にはできないんだ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、15a+10がそのまま正解だよ。両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-064",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(x-4)×(-8)",answer:"-8x+32",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(x-4)×(-8)のように、数がかっこの後ろにあり、しかもマイナスでも、かっこの中のすべての項にかける分配法則を使うよ。",next:"n2"},{id:"n2",type:"check",question:"-8は、かっこの中の何と何にかければいい？",choices:["xだけ","xと-4の両方","-4だけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"外の数は、かっこの中の項の数だけくり返しかける必要があるよ。xだけにかけて-4にかけ忘れると-8x-4になってしまい、間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"そうだね。x×(-8)+(-4)×(-8)と考えるよ。",next:"n4"},{id:"n4",type:"check",question:"-4×(-8) の答えはどれ？",choices:["-32","+32"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-4の「-」は項自体の符号だから、引き算の記号だと思って無視してはいけないよ。負の数どうしをかけると答えはプラスになるから、-4×(-8)=+32だよ。",next:"n4"},{id:"n5",type:"explain",text:"そうだね、-8x+32が正解だよ。項の符号をふくめて両方の項にかけることがポイントだね。",next:"end"}]}},{id:"P0-MOJI-065",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"-3/4(8x+12)",answer:"-6x-9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-3/4(8x+12)を計算します。分配法則は、かっこの外の数をかっこの中の「すべての項」にかけるルールです。",next:"n2"},{id:"n2",type:"check",question:"-3/4は、8xと12のうちどちらにかける？",choices:["8xだけ","8xと12の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則では外の数をかっこの中の全部の項にかけます。8xだけにかけて12を残してしまうと-6x+12のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"-3/4×8xを計算します。8÷4=2なので、-3/4×8x=-6xです。",next:"n4"},{id:"n4",type:"check",question:"-3/4×12 の答えは？",choices:["-9","+9"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"12÷4=3なので-3/4×12=-9です。負の数×正の数は負になります。",next:"n4"},{id:"n5",type:"explain",text:"-6xと-9を合わせて、答えは-6x-9です。両方の項に分配できているか、符号は最後まで確認しましょう。",next:"end"}]}},{id:"P0-MOJI-066",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(5/2 a-1/3)×6",answer:"15a-2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(5/2 a - 1/3)×6 を計算します。外の6を、かっこの中の5/2aと-1/3の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"6は、5/2aと-1/3のうちどちらにかける？",choices:["5/2aだけ","5/2aと-1/3の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則ではかっこの中の全部の項に外の数をかけます。5/2aだけにかけて-1/3を残すと15a-1/3のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"6×5/2aを計算します。6÷2=3なので、6×5/2a=15aです。",next:"n4"},{id:"n4",type:"check",question:"6×(-1/3) の答えは？",choices:["-2","+2"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"6÷3=2なので6×(-1/3)=-2です。正の数×負の数は負になります。",next:"n4"},{id:"n5",type:"explain",text:"15aと-2を合わせて、答えは15a-2です。分数の係数でも両方の項に必ずかけましょう。",next:"end"}]}},{id:"P0-MOJI-067",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(7x+21)÷7",answer:"x+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(7x+21)÷7を計算します。わり算も、かっこの中の「すべての項」を割ります。",next:"n2"},{id:"n2",type:"check",question:"7で割るのは、7xと21のうちどちら？",choices:["7xだけ","7xと21の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの中の全部の項を割る必要があります。7xだけ割って21を残すとx+21のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"7x÷7を計算します。7x÷7=xです。",next:"n4"},{id:"n4",type:"check",question:"21÷7 の答えは？",choices:["3","7"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"21÷7=3です。もう一度わり算を確認しましょう。",next:"n4"},{id:"n5",type:"explain",text:"xと3を合わせて、答えはx+3です。かっこの中の両方の項をきちんと割りましょう。",next:"end"}]}},{id:"P0-MOJI-068",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(8a-4)÷4",answer:"2a-1",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(8a-4)÷4を計算します。かっこの中の「すべての項」を4で割ります。",next:"n2"},{id:"n2",type:"check",question:"4で割るのは、8aと-4のうちどちら？",choices:["8aだけ","8aと-4の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの中の全部の項を割る必要があります。8aだけ割って-4を残すと2a-4のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"8a÷4を計算します。8a÷4=2aです。",next:"n4"},{id:"n4",type:"check",question:"-4÷4 の答えは？",choices:["-1","+1"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-4÷4=-1です。負の数を正の数で割ると負になります。",next:"n4"},{id:"n5",type:"explain",text:"2aと-1を合わせて、答えは2a-1です。符号を最後まで確認しましょう。",next:"end"}]}},{id:"P0-MOJI-069",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(12x+9)÷3",answer:"4x+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(12x+9)÷3を計算します。かっこの中の「すべての項」を3で割ります。",next:"n2"},{id:"n2",type:"check",question:"3で割るのは、12xと9のうちどちら？",choices:["12xだけ","12xと9の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの中の全部の項を割る必要があります。12xだけ割って9を残すと4x+9のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"12x÷3を計算します。12x÷3=4xです。",next:"n4"},{id:"n4",type:"check",question:"9÷3 の答えは？",choices:["3","6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"9÷3=3です。もう一度わり算を確認しましょう。",next:"n4"},{id:"n5",type:"explain",text:"4xと3を合わせて、答えは4x+3です。かっこの中の両方の項をきちんと割りましょう。",next:"end"}]}},{id:"P0-MOJI-070",subunit:"分配法則と一次式",difficulty:"★2標準",problem_text:"(12a-18)÷(-6)",answer:"-2a+3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(12a-18)÷(-6)を計算します。かっこの中の「すべての項」を-6で割ります。",next:"n2"},{id:"n2",type:"check",question:"-6で割るのは、12aと-18のうちどちら？",choices:["12aだけ","12aと-18の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこの中の全部の項を割る必要があります。12aだけ割って-18を残すと-2a-18のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"12a÷(-6)を計算します。正の数を負の数で割ると符号は負になるので、12a÷(-6)=-2aです。",next:"n4"},{id:"n4",type:"check",question:"-18÷(-6) の答えは？",choices:["3","-3"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"負の数を負の数で割ると符号は正になります。-18÷(-6)=3です。「もとがマイナスだから答えもマイナス」ではありません。",next:"n4"},{id:"n5",type:"explain",text:"-2aと3を合わせて、答えは-2a+3です。負の数で割るときの符号変化を毎回確認しましょう。",next:"end"}]}},{id:"P0-MOJI-071",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"(x+7)/3 ×3",answer:"x+7",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(x+7)/3×3を計算します。分母の3と外の×3は約分できます。",next:"n2"},{id:"n2",type:"check",question:"3/3を約分すると1になる。この「1」は、xと7のどちらにかかる？",choices:["xだけ","xと7の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分の効果はかっこの中の全部の項に及びます。xだけに効かせて7をそのまま残すとx+7/3のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"1×(x+7)=x+7です。分母と外の数が同じときは、先に約分すると計算が簡単になります。",next:"n4"},{id:"n4",type:"explain",text:"答えはx+7です。分数のかっこの計算でも、分配・約分はかっこの中のすべての項に及ぶことを忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-072",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"(7a-2)/4 ×8",answer:"14a-4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(7a-2)/4×8を計算します。まず8÷4=2と約分します。",next:"n2"},{id:"n2",type:"check",question:"約分した2は、分子の7aと-2のどちらにかける？",choices:["7aだけ","7aと-2の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分した数もかっこの中の全部の項にかけます。7aだけにかけて-2を残すと14a-2のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"7a×2を計算します。7a×2=14aです。",next:"n4"},{id:"n4",type:"check",question:"-2×2 の答えは？",choices:["-4","-16"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-2×2=-4です。約分した後の数（2）でかけ算することを確認しましょう。",next:"n4"},{id:"n5",type:"explain",text:"14aと-4を合わせて、答えは14a-4です。約分してから分配する順番を守りましょう。",next:"end"}]}},{id:"P0-MOJI-073",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"18×(3a-4)/9",answer:"6a-8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"18×(3a-4)/9を計算します。まず18÷9=2と約分します。",next:"n2"},{id:"n2",type:"check",question:"約分した2は、分子の3aと-4のどちらにかける？",choices:["3aだけ","3aと-4の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分した数もかっこの中の全部の項にかけます。3aだけにかけて-4を残すと6a-4のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"3a×2を計算します。3a×2=6aです。",next:"n4"},{id:"n4",type:"check",question:"-4×2 の答えは？",choices:["-8","+8"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-4×2=-8です。負の数×正の数は負になります。",next:"n4"},{id:"n5",type:"explain",text:"6aと-8を合わせて、答えは6a-8です。数が前にある形でも、約分してから分配する順番は同じです。",next:"end"}]}},{id:"P0-MOJI-074",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"(5x+3)/6 ×(-12)",answer:"-10x-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(5x+3)/6×(-12)を計算します。まず-12÷6=-2と約分します。",next:"n2"},{id:"n2",type:"check",question:"約分した-2は、分子の5xと3のどちらにかける？",choices:["5xだけ","5xと3の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分した数もかっこの中の全部の項にかけます。5xだけにかけて3を残すと-10x+3のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"5x×(-2)を計算します。5x×(-2)=-10xです。",next:"n4"},{id:"n4",type:"check",question:"3×(-2) の答えは？",choices:["-6","+6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"3×(-2)=-6です。もとの項がプラスでも、負の数をかければ符号は変わります。「プラスの項だから符号はそのまま」ではありません。",next:"n4"},{id:"n5",type:"explain",text:"-10xと-6を合わせて、答えは-10x-6です。負の数をかけるときは項ごとに符号の変化を確認しましょう。",next:"end"}]}},{id:"P0-MOJI-075",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"(7x-2)/4 ×(-8)",answer:"-14x+4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(7x-2)/4×(-8)を計算します。まず-8÷4=-2と約分します。",next:"n2"},{id:"n2",type:"check",question:"約分した-2は、分子の7xと-2のどちらにかける？",choices:["7xだけ","7xと-2の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分した数もかっこの中の全部の項にかけます。7xだけにかけて-2を残すと-14x-2のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"7x×(-2)を計算します。7x×(-2)=-14xです。",next:"n4"},{id:"n4",type:"check",question:"-2×(-2) の答えは？",choices:["+4","-4"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"負の数×負の数は正になります。-2×(-2)=+4です。「もとがマイナスの項だから符号はそのまま」ではありません。",next:"n4"},{id:"n5",type:"explain",text:"-14xと+4を合わせて、答えは-14x+4です。マイナス×マイナスがプラスになることを毎回確認しましょう。",next:"end"}]}},{id:"P0-MOJI-076",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"(-20)×(3a+2)/4",answer:"-15a-10",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-20)×(3a+2)/4を計算します。まず-20÷4=-5と約分します。",next:"n2"},{id:"n2",type:"check",question:"約分した-5は、分子の3aと2のどちらにかける？",choices:["3aだけ","3aと2の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"約分した数もかっこの中の全部の項にかけます。3aだけにかけて2を残すと-15a+2のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"3a×(-5)を計算します。3a×(-5)=-15aです。",next:"n4"},{id:"n4",type:"check",question:"2×(-5) の答えは？",choices:["-10","+10"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2×(-5)=-10です。正の項に負の数をかけると符号は負になります。",next:"n4"},{id:"n5",type:"explain",text:"-15aと-10を合わせて、答えは-15a-10です。数が先にある形でも、約分してから分配する手順は同じです。",next:"end"}]}},{id:"P0-MOJI-077",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"5x+3(x-2)",answer:"8x-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5x+3(x-2)を計算します。まず3(x-2)のかっこを分配法則で開きます。",next:"n2"},{id:"n2",type:"check",question:"3は、xと-2のどちらにかける？",choices:["xだけ","xと-2の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則ではかっこの中の全部の項にかけます。xだけにかけて-2を残すと5x+3x-2のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"3(x-2)=3x-6です。式全体は5x+3x-6になりました。",next:"n4"},{id:"n4",type:"check",question:"5xと3xと-6のうち、まとめられる同類項はどれ？",choices:["5xと3xだけ","3xと-6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"同類項はxの項どうしだけです。5xと3xはまとめられますが、-6は数の項なのでxの項とはまとめられません。",next:"n4"},{id:"n5",type:"explain",text:"5x+3x=8xとなり、-6はそのまま残るので、答えは8x-6です。分配してから同類項をまとめる順番を守りましょう。",next:"end"}]}},{id:"P0-MOJI-078",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"-3(2a+5)+7a",answer:"a-15",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-3(2a+5)+7aを計算します。まず-3(2a+5)のかっこを分配法則で開きます。",next:"n2"},{id:"n2",type:"check",question:"-3は、2aと5のどちらにかける？",choices:["2aだけ","2aと5の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則ではかっこの中の全部の項にかけます。2aだけにかけて5を残すと-6a+5+7aのような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"-3(2a+5)=-6a-15です。式全体は-6a-15+7aになりました。",next:"n4"},{id:"n4",type:"check",question:"-6aと7aをまとめると？",choices:["a（-6+7=1）","13a（6+7=13）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"同類項をまとめるときは符号も含めて計算します。-6+7=1なので、-6a+7a=aです。符号を無視して6+7=13とするのは誤りです。",next:"n4"},{id:"n5",type:"explain",text:"-6a+7a=aとなり、-15はそのまま残るので、答えはa-15です。負の数の分配は符号を一つずつ確認しながら進めましょう。",next:"end"}]}},{id:"P0-MOJI-079",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"3(a+4)+2(4a-3)",answer:"11a+6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3(a+4)+2(4a-3)を計算します。2つのかっこをそれぞれ分配法則で開きます。",next:"n2"},{id:"n2",type:"check",question:"3(a+4)を分配すると3aと12のどちらができる？",choices:["3aだけ","3aと12の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則ではかっこの中の全部の項にかけます。aだけにかけて4を残すと3a+4のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"3(a+4)=3a+12、2(4a-3)=8a-6です。式全体は3a+12+8a-6になりました。",next:"n4"},{id:"n4",type:"check",question:"12と-6をまとめると？",choices:["6（12-6=6）","18（12+6=18）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"数の項をまとめるときも符号を含めて計算します。12+(-6)=6なので、答えは6です。符号を無視して12+6=18とするのは誤りです。",next:"n4"},{id:"n5",type:"explain",text:"3a+8a=11a、12-6=6となるので、答えは11a+6です。2つのかっこを両方きちんと展開してから同類項をまとめましょう。",next:"end"}]}},{id:"P0-MOJI-080",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"3(3x-2)+2(x-7)",answer:"11x-20",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3(3x-2)+2(x-7)を計算します。2つのかっこをそれぞれ分配法則で開きます。",next:"n2"},{id:"n2",type:"check",question:"3(3x-2)を分配すると9xと-6のどちらができる？",choices:["9xだけ","9xと-6の両方"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則ではかっこの中の全部の項にかけます。3xだけにかけて-2を残すと9x-2のような間違いになります。",next:"n2"},{id:"n3",type:"explain",text:"3(3x-2)=9x-6、2(x-7)=2x-14です。式全体は9x-6+2x-14になりました。",next:"n4"},{id:"n4",type:"check",question:"-6と-14をまとめると？",choices:["-20（-6-14=-20）","-8（14-6=8で負）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"負の数どうしの和は絶対値を足してマイナスをつけます。-6+(-14)=-20です。差を取って-8とするのは誤りです。",next:"n4"},{id:"n5",type:"explain",text:"9x+2x=11x、-6-14=-20となるので、答えは11x-20です。負の数どうしの同類項は符号ごと丁寧に足しましょう。",next:"end"}]}},{id:"P0-MOJI-081",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"8(2y-5)+5(-3y+4)",answer:"y-20",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"8(2y-5)+5(-3y+4) を計算します。かっこの前の数は、かっこの中の「全部の項」にかけるのが分配法則のルールです。",next:"n2"},{id:"n2",type:"check",question:"5(-3y+4) を分配法則で展開すると、どれが正しい？",choices:["-15y+20（両方の項に5をかける）","-15y（-3yだけに5をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"5は-3yだけでなく+4にもかける必要があります。5×(-3y)=-15y、5×4=20 なので、-15y+20 が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"同じように8(2y-5)も展開すると16y-40。合わせると 16y-40-15y+20 になります。",next:"n4"},{id:"n4",type:"check",question:"16y-40-15y+20 の定数項(-40と+20)をまとめると？",choices:["-20","+60"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを足すと間違えます。-40+20は「40から20を引いて、大きい方の符号(マイナス)をつける」ので-20です。",next:"n4"},{id:"n5",type:"explain",text:"文字の項も16y-15y=yとまとまるので、最終的な答えは y-20 です。",next:"end"}]}},{id:"P0-MOJI-082",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"6(a-3)-5(a+4)",answer:"a-38",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"6(a-3)-5(a+4) を計算します。-5はかっこの中の「両方の項」a と +4 の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"-5(a+4) を分配法則で展開すると、どれが正しい？",choices:["-5a-20（両方の項に-5をかける）","-5a+4（aだけに-5をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-5はaだけでなく+4にもかけます。-5×a=-5a、-5×4=-20 なので、-5a-20 が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"6(a-3)も展開すると6a-18。合わせると 6a-18-5a-20 になります。",next:"n4"},{id:"n4",type:"check",question:"6a-18-5a-20 の定数項(-18と-20)をまとめると？",choices:["-38","+2"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを引き算すると間違えます。-18と-20はどちらもマイナスなので、足して-38です。",next:"n4"},{id:"n5",type:"explain",text:"aの項も6a-5a=aとまとまるので、最終的な答えは a-38 です。",next:"end"}]}},{id:"P0-MOJI-083",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"4(-3a+2)-6(2a-5)",answer:"-24a+38",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4(-3a+2)-6(2a-5) を計算します。-6はかっこの中の「両方の項」2a と -5 の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"-6(2a-5) を分配法則で展開すると、どれが正しい？",choices:["-12a+30（-6×(-5)=+30と符号も正しく計算）","-12a-5（-5をそのまま写すだけ）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-5は写すだけでなく-6をかけ算します。-6×(-5)は負×負でプラスになるので+30です。-12a+30が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"4(-3a+2)も展開すると-12a+8。合わせると -12a+8-12a+30 になります。",next:"n4"},{id:"n4",type:"check",question:"-12a+8-12a+30 の定数項(8と30)をまとめると？",choices:["+38","+22"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して適当に足し引きすると間違えます。8と30はどちらもプラスなので、そのまま足して38です。",next:"n4"},{id:"n5",type:"explain",text:"aの項も-12a-12a=-24aとまとまるので、最終的な答えは -24a+38 です。",next:"end"}]}},{id:"P0-MOJI-084",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"-2(9x-4)-3(7x+2)",answer:"-39x+2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-2(9x-4)-3(7x+2) を計算します。-2はかっこの中の「両方の項」9x と -4 の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"-2(9x-4) を分配法則で展開すると、どれが正しい？",choices:["-18x+8（-2×(-4)=+8と符号も正しく計算）","-18x-4（-4をそのまま写すだけ）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-4は写すだけでなく-2をかけ算します。-2×(-4)は負×負でプラスになるので+8です。-18x+8が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"-3(7x+2)も展開すると-21x-6。合わせると -18x+8-21x-6 になります。",next:"n4"},{id:"n4",type:"check",question:"-18x+8-21x-6 の定数項(8と-6)をまとめると？",choices:["+2","-14"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを足すと間違えます。8-6は「8から6を引いて」+2です。",next:"n4"},{id:"n5",type:"explain",text:"xの項も-18x-21x=-39xとまとまるので、最終的な答えは -39x+2 です。",next:"end"}]}},{id:"P0-MOJI-085",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"4/3(6x-9)+1/2(-8x+4)",answer:"4x-10",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4/3(6x-9)+1/2(-8x+4) を計算します。分数の係数でも、かっこの中の「両方の項」にかけるルールは同じです。",next:"n2"},{id:"n2",type:"check",question:"1/2(-8x+4) を分配法則で展開すると、どれが正しい？",choices:["-4x+2（両方の項に1/2をかける）","-4x（-8xだけに1/2をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1/2は-8xだけでなく+4にもかけます。1/2×4=2 なので、-4x+2 が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"4/3(6x-9)も展開すると8x-12。合わせると 8x-12-4x+2 になります。",next:"n4"},{id:"n4",type:"check",question:"8x-12-4x+2 の定数項(-12と+2)をまとめると？",choices:["-10","+10"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを計算すると間違えます。-12+2は「12から2を引いて、大きい方の符号(マイナス)をつける」ので-10です。",next:"n4"},{id:"n5",type:"explain",text:"xの項も8x-4x=4xとまとまるので、最終的な答えは 4x-10 です。",next:"end"}]}},{id:"P0-MOJI-086",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"1/3(9x-6)-1/4(8x-12)",answer:"x+1",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"1/3(9x-6)-1/4(8x-12) を計算します。-1/4はかっこの中の「両方の項」8x と -12 の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"-1/4(8x-12) を分配法則で展開すると、どれが正しい？",choices:["-2x+3（-1/4×(-12)=+3と符号も正しく計算）","-2x-3（-12をそのまま写すだけ）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-12は写すだけでなく-1/4をかけ算します。-1/4×(-12)は負×負でプラスになるので+3です。-2x+3が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"1/3(9x-6)も展開すると3x-2。合わせると 3x-2-2x+3 になります。",next:"n4"},{id:"n4",type:"check",question:"3x-2-2x+3 の定数項(-2と+3)をまとめると？",choices:["+1","+5"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを足すと間違えます。-2+3は「3から2を引いて」+1です。",next:"n4"},{id:"n5",type:"explain",text:"xの項も3x-2x=xとまとまるので、最終的な答えは x+1 です。",next:"end"}]}},{id:"P0-MOJI-087",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"3/5(15a+10)+4(-3+a)",answer:"13a-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3/5(15a+10)+4(-3+a) を計算します。4(-3+a)は順番が「-3が先、aが後」ですが、4は両方の項にかけます。",next:"n2"},{id:"n2",type:"check",question:"4(-3+a) を分配法則で展開すると、どれが正しい？",choices:["-12+4a（両方の項に4をかける）","-12（-3だけに4をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"順番が逆でも、4は-3だけでなくaにもかけます。4×a=4a なので、-12+4a が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"3/5(15a+10)も展開すると9a+6。合わせると 9a+6-12+4a になります。",next:"n4"},{id:"n4",type:"check",question:"9a+6-12+4a の定数項(6と-12)をまとめると？",choices:["-6","+18"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを足すと間違えます。6-12は「12から6を引いて、大きい方の符号(マイナス)をつける」ので-6です。",next:"n4"},{id:"n5",type:"explain",text:"aの項も9a+4a=13aとまとまるので、最終的な答えは 13a-6 です。",next:"end"}]}},{id:"P0-MOJI-088",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"1/2(6y-4)+1/2(2y+8)",answer:"4y+2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"1/2(6y-4)+1/2(2y+8) を計算します。同じ1/2でも、それぞれのかっこの「両方の項」にかける必要があります。",next:"n2"},{id:"n2",type:"check",question:"1/2(2y+8) を分配法則で展開すると、どれが正しい？",choices:["y+4（両方の項に1/2をかける）","y（2yだけに1/2をかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1/2は2yだけでなく+8にもかけます。1/2×8=4 なので、y+4 が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"1/2(6y-4)も展開すると3y-2。合わせると 3y-2+y+4 になります。",next:"n4"},{id:"n4",type:"check",question:"3y-2+y+4 の定数項(-2と+4)をまとめると？",choices:["+2","-6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを計算すると間違えます。-2+4は「4から2を引いて」+2です。",next:"n4"},{id:"n5",type:"explain",text:"yの項も3y+y=4yとまとまるので、最終的な答えは 4y+2 です。",next:"end"}]}},{id:"P0-MOJI-089",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"-1/2(-4+6x)-2/3(-3x+9)",answer:"-x-4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-1/2(-4+6x)-2/3(-3x+9) を計算します。かっこの中の順番が「定数が先、xの項が後」でも、両方の項にかけ算します。",next:"n2"},{id:"n2",type:"check",question:"-2/3(-3x+9) を分配法則で展開すると、どれが正しい？",choices:["2x-6（-2/3×9=-6と符号も正しく計算）","2x+9（+9をそのまま写すだけ）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"+9は写すだけでなく-2/3をかけ算します。-2/3×9=-6 なので、2x-6 が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"-1/2(-4+6x)も展開すると2-3x。合わせると 2-3x+2x-6 になります。",next:"n4"},{id:"n4",type:"check",question:"2-3x+2x-6 の定数項(2と-6)をまとめると？",choices:["-4","+8"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを足すと間違えます。2-6は「6から2を引いて、大きい方の符号(マイナス)をつける」ので-4です。",next:"n4"},{id:"n5",type:"explain",text:"xの項も-3x+2x=-xとまとまるので、最終的な答えは -x-4 です。",next:"end"}]}},{id:"P0-MOJI-090",subunit:"分配法則と一次式",difficulty:"★3応用",problem_text:"4/3(3x-3/4)-1/2(4x-2)",answer:"2x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4/3(3x-3/4)-1/2(4x-2) を計算します。-1/2はかっこの中の「両方の項」4x と -2 の両方にかけます。",next:"n2"},{id:"n2",type:"check",question:"-1/2(4x-2) を分配法則で展開すると、どれが正しい？",choices:["-2x+1（-1/2×(-2)=+1と符号も正しく計算）","-2x-2（-2をそのまま写すだけ）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-2は写すだけでなく-1/2をかけ算します。-1/2×(-2)は負×負でプラスになるので+1です。-2x+1が正しい展開です。",next:"n2"},{id:"n3",type:"explain",text:"4/3(3x-3/4)も展開すると4x-1。合わせると 4x-1-2x+1 になります。",next:"n4"},{id:"n4",type:"check",question:"4x-1-2x+1 の定数項(-1と+1)をまとめると？",choices:["0（打ち消し合う）","-2"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"符号を無視して数字だけを引き算すると間違えます。-1+1は同じ大きさで符号が逆なので、打ち消し合って0になります。",next:"n4"},{id:"n5",type:"explain",text:"xの項は4x-2x=2xで、定数項は0なので0は書きません。最終的な答えは 2x です。",next:"end"}]}},{id:"P0-MOJI-091",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-5x-7x",answer:"-12x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-5x-7x を計算します。同じ文字xの項なので、係数(-5と-7)だけを計算してまとめます。",next:"n2"},{id:"n2",type:"check",question:"-5と-7を足すと、符号はどうなる？",choices:["マイナスのまま(-12)","係数の差でプラスになる(2)"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-5も-7もどちらもマイナスの数です。マイナスどうしを足すと、さらに大きなマイナスになります。5+7=12なので、答えは-12です。",next:"n2"},{id:"n3",type:"explain",text:"-5+(-7)=-12 なので、係数は-12。文字xを付けると、答えは -12x になります。",next:"end"}]}},{id:"P0-MOJI-092",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"6a-13a",answer:"-7a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"6a-13a を計算します。同じ文字aの項なので、係数(6と-13)だけを計算してまとめます。",next:"n2"},{id:"n2",type:"check",question:"6+(-13)の符号はどうなる？",choices:["マイナスになる(-7)","符号を気にせず引き算した数になる(7)"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を無視して数字だけ引き算すると間違えます。6と13では絶対値の大きい13の符号（マイナス）が答え全体の符号になるので、6-13=-7です。",next:"n2"},{id:"n3",type:"explain",text:"6-13=-7 なので、係数は-7。文字aを付けると、答えは -7a になります。",next:"end"}]}},{id:"P0-MOJI-093",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-8a+3a",answer:"-5a",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-8a+3a を計算します。同じ文字aの項なので、係数(-8と3)だけを計算してまとめます。",next:"n2"},{id:"n2",type:"check",question:"-8+3の符号はどうなる？",choices:["マイナスになる(-5)","符号を気にせず引き算した数になる(5)"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を無視して数字だけ引き算すると間違えます。8と3では絶対値の大きい8の符号（マイナス）が答え全体の符号になるので、-8+3=-5です。",next:"n2"},{id:"n3",type:"explain",text:"-8+3=-5 なので、係数は-5。文字aを付けると、答えは -5a になります。",next:"end"}]}},{id:"P0-MOJI-094",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"y+y",answer:"2y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"y+y を計算します。yには係数1が省略されているので、これは1y+1yと同じ意味です。",next:"n2"},{id:"n2",type:"check",question:"y+y（足し算）と y×y（かけ算）、2yになるのはどちら？",choices:["y+y（足し算）","y×y（かけ算）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"y×y（同じ文字を2回かける）はy²になります。2yになるのは、y+y（同じ文字を2回足す）のほうです。",next:"n2"},{id:"n3",type:"explain",text:"1y+1yの係数どうしを足すと、1+1=2。文字yを付けると、答えは 2y になります。",next:"end"}]}},{id:"P0-MOJI-095",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-5x+9x-6x",answer:"-2x",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-5x+9x-6x を計算します。項が3つあるので、1つずつ順番に係数を計算していきます。",next:"n2"},{id:"n2",type:"check",question:"まず -5+9 を計算すると？",choices:["4","14"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を見落とすと間違えます。-5と+9では絶対値の大きい9の符号（プラス）が答えの符号になるので、-5+9=4です。",next:"n2"},{id:"n3",type:"explain",text:"次に、その4と最後の項-6を足します。",next:"n4"},{id:"n4",type:"check",question:"4+(-6) はいくつ？",choices:["-2","8"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"最後の項を数え忘れたり、符号を間違えたりすると答えがずれます。4-6は「6から4を引いて、大きい方の符号(マイナス)をつける」ので-2です。",next:"n4"},{id:"n5",type:"explain",text:"3つの項をすべて計算すると係数は-2。文字xを付けると、最終的な答えは -2x になります。",next:"end"}]}},{id:"P0-MOJI-096",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"5a-9a+4a",answer:"0",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5a-9a+4a を計算します。まず係数(5,-9,4)だけを取り出して計算します。",next:"n2"},{id:"n2",type:"check",question:"5-9+4 を計算すると？",choices:["0","18"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を無視してすべて足すと間違えます。5-9=-4、-4+4=0 と順番に符号を確認しながら計算します。",next:"n2"},{id:"n3",type:"explain",text:"係数が0になりました。ここで0aと書いてよいか考えます。",next:"n4"},{id:"n4",type:"check",question:"係数が0になったとき、答えの書き方はどちらが正しい？",choices:["0（文字は書かない）","0a（文字を残す）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"0×aは0なので、文字aを残す意味がありません。係数が0になったときは、文字を書かずに「0」とだけ書きます。",next:"n4"},{id:"n5",type:"explain",text:"係数の計算結果が0なので、文字aは書かず、最終的な答えは 0 です。",next:"end"}]}},{id:"P0-MOJI-097",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"7y-3+8y",answer:"15y-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"7y-3+8yのような式は、まず『文字の項』と『定数項』に分けて見るのがコツだよ。7yと8yは同じ文字yがついているから同類項、-3は文字がついていない定数項だ。",next:"n2"},{id:"n2",type:"check",question:"7y、8y、-3のうち、まとめられる同類項の組はどれ？",choices:["7yと8y","8yと-3","7y、8y、-3の全部"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"同類項とは『同じ文字の部分がそろっている項』のこと。-3には文字yがついていないから、7yや8yの仲間には入れられないよ。まとめられるのは7yと8yだけ。",next:"n2"},{id:"n3",type:"explain",text:"7y+8y=15y。ここまでは正しい。次に定数項-3を扱うよ。-3は文字の項とはまとめられないから、符号をそのままつけて式の最後にくっつける。",next:"n4"},{id:"n4",type:"check",question:"文字の項15yと定数項-3を合わせると、正しい答えはどれ？",choices:["15y-3","15y+3","12y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-3の『-』は符号込みで1つの項なので、勝手に+3に変えたり、数字だけ足して12yにしたりしてはいけないよ。符号をそのまま残して15y-3とするのが正解。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。同類項（同じ文字の項）どうしだけをまとめ、定数項は符号をそのままつけて残す。7y-3+8y=15y-3が正解だよ。",next:"end"}]}},{id:"P0-MOJI-098",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"2b+6-9b",answer:"-7b+6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2b+6-9bを整理するよ。-9bの『-』は、9bという項の符号として最初からくっついているんだ。符号を切り離して考えてはいけないよ。",next:"n2"},{id:"n2",type:"check",question:"2bと-9bをまとめると、正しい計算はどれ？",choices:["2b-9b=-7b","2b+9b=11b（符号は無視）","9b-2b=7b（大きい方から引く）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-9bの『-』を無視して2b+9bとしたり、数字の大小だけで9-2としたりしてはダメだよ。-9bは『マイナス9b』という1つの項。2bにこの-9bを足すので、2b-9b=-7bとなる。",next:"n2"},{id:"n3",type:"explain",text:"2b-9b=-7b。これで文字の項が終わったよ。次は定数項+6。これは文字の項とは別のなかまだから、符号+のままそのまま残す。",next:"n4"},{id:"n4",type:"check",question:"-7bと+6を合わせた最終的な答えはどれ？",choices:["-7b+6","-7b-6","7b+6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"定数項+6の符号を勝手に-6に変えたり、文字の項の符号を消したりしないように注意しよう。正しくは-7b+6だよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。マイナスのついた項は、符号込みで1つの項として計算する。2b+6-9b=-7b+6が正解だよ。",next:"end"}]}},{id:"P0-MOJI-099",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-2+7x-4-x",answer:"6x-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-2+7x-4-xを整理するよ。ここで注意したいのが-x。数字が見えないけど、これは『-1×x』、つまり係数1の項なんだ。",next:"n2"},{id:"n2",type:"check",question:"7xと-xをまとめると、正しい計算はどれ？",choices:["7x-x=6x","7xだけを残す（-xは無視）","7x+x=8x（-xの符号を無視）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-xは『数字がついていないから項じゃない』わけではなく、『-1x』という係数1の項だよ。無視したり、符号を消して足したりせず、符号込みでまとめると7x-x=6xになる。",next:"n2"},{id:"n3",type:"explain",text:"7x-x=6x。これで文字の項が終わったよ。次は定数項-2と-4をまとめる。",next:"n4"},{id:"n4",type:"check",question:"-2と-4をまとめると、正しい計算はどれ？",choices:["-2-4=-6","-2-4=+6","2+4=6"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"負の数どうしを足すと、絶対値の和に負の符号がつく。-2-4は-(2+4)=-6だよ。符号を+に変えないように注意しよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。係数が見えない-xも1つの項として扱い、定数項は符号込みでまとめる。-2+7x-4-x=6x-6が正解だよ。",next:"end"}]}},{id:"P0-MOJI-100",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-3a+2+7a+6",answer:"4a+8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-3a+2+7a+6を整理するよ。まず式を見直して、-3aの符号がマイナスであることをしっかり確認しよう。急いで写すとプラスと見間違えやすいところだよ。",next:"n2"},{id:"n2",type:"check",question:"-3aと7aをまとめると、正しい計算はどれ？",choices:["-3a+7a=4a","-3a+7a=-4a（符号を逆にする）","3a+7a=10a（マイナスを見落とす）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-3aの『-』は消してはいけないし、符号を逆にしてもいけないよ。-3に7を足すと4になる（-3+7=4）ので、-3a+7a=4aが正しいよ。",next:"n2"},{id:"n3",type:"explain",text:"-3a+7a=4a。これで文字の項が終わったよ。次は定数項2と6をまとめる。",next:"n4"},{id:"n4",type:"check",question:"定数項2と6をまとめると、正しい計算はどれ？",choices:["2+6=8","2+6=4（符号ミス）","6-2=4"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2と6はどちらも正の数だから、そのまま足せばいい。2+6=8だよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。写し間違いや符号ミスに注意しながら、文字の項どうし・定数項どうしをまとめる。-3a+2+7a+6=4a+8が正解だよ。",next:"end"}]}},{id:"P0-MOJI-101",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"-6b+3-8-6b",answer:"-12b-5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-6b+3-8-6bを整理するよ。同じ-6bが2回出てくるけど、これは『-6bが2個ある』という意味。りんごが3個と3個あったら合わせて6個になるのと同じだよ。",next:"n2"},{id:"n2",type:"check",question:"-6bと-6bをまとめると、正しい計算はどれ？",choices:["-6b-6b=-12b","同じ項だからそのまま-6b","-6b-6b=12b（符号を逆にする）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"同じ項が2つあるときは『そのまま』にせず、必ず足し合わせるよ。-6bが2個で-6b-6b=-12b。符号もマイナスのまま変わらないよ。",next:"n2"},{id:"n3",type:"explain",text:"-6b-6b=-12b。これで文字の項が終わったよ。次は定数項3と-8をまとめる。-8の『-』は独立したものではなく、8という項に最初からついている符号だよ。",next:"n4"},{id:"n4",type:"check",question:"定数項3と-8をまとめると、正しい計算はどれ？",choices:["3-8=-5","3+8=11（符号を無視）","3-8=5"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-8の『-』を無視して3+8としてはいけないよ。3から8を引く（3-8）と考えると、答えは-5になる。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。同じ文字の項が複数あってもそのままにせず必ず足し合わせ、定数項は符号込みでまとめる。-6b+3-8-6b=-12b-5が正解だよ。",next:"end"}]}},{id:"P0-MOJI-102",subunit:"同類項をまとめる",difficulty:"★1基礎",problem_text:"8+y-5y-4",answer:"-4y+4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"8+y-5y-4を整理するよ。式の先頭にあるyに注目。数字が見えないけど、これは『1×y』、つまり係数1の項なんだ。",next:"n2"},{id:"n2",type:"check",question:"yと-5yをまとめると、正しい計算はどれ？",choices:["y-5y=-4y","-5yだけを残す（yは無視）","y+5y=6y（-5yの符号を無視）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"yは『数字がついていないから項じゃない』わけではなく、『1y』という係数1の項だよ。無視したり、符号を消して足したりせず、符号込みでまとめると1y-5y=-4yになる。",next:"n2"},{id:"n3",type:"explain",text:"y-5y=-4y。これで文字の項が終わったよ。次は定数項8と-4をまとめる。",next:"n4"},{id:"n4",type:"check",question:"定数項8と-4をまとめると、正しい計算はどれ？",choices:["8-4=4","8-4=-4（符号ミス）","8+4=12"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"8から4を引くので8-4=4だよ。符号を勝手にマイナスに変えないように注意しよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。係数が見えないyも1つの項として扱い、定数項は符号込みでまとめる。8+y-5y-4=-4y+4が正解だよ。",next:"end"}]}},{id:"P0-MOJI-103",subunit:"式の値（代入）",difficulty:"★1基礎",problem_text:"y=5のとき 4y の値。",answer:"20",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4yという書き方には、実は『×』が隠れているんだ。文字式では×を省略する約束があって、4yは本当は『4×y』という意味だよ。",next:"n2"},{id:"n2",type:"check",question:"4yを×を省略せずに書くとどれ？",choices:["4+y","4×y","4とyを並べただけ"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字式で、数字と文字がくっついて書かれているときは『×』が省略されているんだ。4yは4+yでも、ただ並べただけでもなく、4×yという意味だよ。",next:"n2"},{id:"n3",type:"explain",text:"4yは4×yということが分かったね。y=5のときの値を求めるには、このyの部分に5を入れる（代入する）。すると4×5になるよ。",next:"n4"},{id:"n4",type:"check",question:"4×5を計算すると？",choices:["9","20","45"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"4×5は『4を5回足す』かけ算の計算だよ。4+4+4+4+4=20。足し算(4+5=9)や数字を並べる(45)のとは違うよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。4yは4×yの省略形。yに5を代入すると4×5=20になる。文字式の×省略のルールを忘れないようにしようね。",next:"end"}]}},{id:"P0-MOJI-104",subunit:"式の値（代入）",difficulty:"★1基礎",problem_text:"y=5のとき 2+3y の値。",answer:"17",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2+3yにy=5を代入すると、2+3×5になるよ。ここでのポイントは『どの順番で計算するか』だ。",next:"n2"},{id:"n2",type:"check",question:"2+3×5では、たし算とかけ算、どちらを先に計算する？",choices:["たし算の2+3を先に計算する","かけ算の3×5を先に計算する","どちらからでもよい"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"計算の決まりでは、かけ算・わり算はたし算・ひき算より先に計算するんだったね。だから2+3×5では、先に3×5を計算するよ。",next:"n2"},{id:"n3",type:"explain",text:"3×5=15。かけ算を先に計算できたね。",next:"n4"},{id:"n4",type:"check",question:"2+15を計算すると？",choices:["17","25","10"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2+15は普通のたし算だよ。2に15を足すと17になる。先に2+3=5を計算して5×5=25としてしまうのは順序のミスだから気をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。代入したら2+3×5の形になり、かけ算を先に計算する。2+3y（y=5）=2+15=17が正解だよ。",next:"end"}]}},{id:"P0-MOJI-105",subunit:"式の値（代入）",difficulty:"★1基礎",problem_text:"b=-3のとき 4b+9 の値。",answer:"-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4b+9にb=-3を代入するよ。負の数を代入するときは、必ずかっこをつけるのが決まりだ。4b+9 → 4×(-3)+9のようにね。",next:"n2"},{id:"n2",type:"check",question:"b=-3を4bに正しく代入するとどれ？",choices:["4×(-3)","4-3","4×3"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこをつけずに数字だけ書き並べると、かけ算だったはずの式がたし算のように見えてしまったり、符号が消えたりするよ。b=-3は必ず(-3)とかっこをつけて4bの部分に入れよう。",next:"n2"},{id:"n3",type:"explain",text:"4×(-3)+9の形になったね。まずかけ算の4×(-3)を計算しよう。正の数×負の数はマイナスになるから、4×(-3)=-12だよ。",next:"n4"},{id:"n4",type:"check",question:"-12+9を計算すると？",choices:["-3","10","21"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-12+9は、絶対値の大きい-12の符号が残り、12-9=3なので-3になるよ。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。負の数を代入するときは必ずかっこをつける。4×(-3)+9=-12+9=-3が正解だよ。",next:"end"}]}},{id:"P0-MOJI-106",subunit:"式の値（代入）",difficulty:"★1基礎",problem_text:"b=-3のとき 2-b の値。",answer:"5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2-bにb=-3を代入するよ。負の数を代入するときは必ずかっこをつけるので、2-b → 2-(-3)になる。",next:"n2"},{id:"n2",type:"check",question:"b=-3を2-bに正しく代入するとどれ？",choices:["2-(-3)","2-3","2+3のまま代入"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこをつけずに2-3としてしまうと、-3のマイナスが1つ消えてしまうよ。b=-3は必ず(-3)とかっこをつけて2-bのbの部分に入れよう。",next:"n2"},{id:"n3",type:"explain",text:"2-(-3)の形になったね。『負の数を引く』のは『その数を足す』のと同じという決まりがあるので、減法を加法に直すと2+3になるよ。",next:"n4"},{id:"n4",type:"check",question:"2+3を計算すると？",choices:["5","-1","-5"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2+3は普通のたし算だよ。2に3を足すと5になる。かっこを忘れて2-3=-1としたり、符号処理を誤って-5としたりしないように気をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。負の数を代入するときはかっこをつけ、『負の数を引く』は『足す』に直す。2-(-3)=2+3=5が正解だよ。",next:"end"}]}},{id:"P0-MOJI-107",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"b=-5のとき -3-5b の値。",answer:"22",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-3-5bにb=-5を代入するよ。かっこをつけて代入すると-3-5×(-5)になる。まずかけ算を先に計算しよう。",next:"n2"},{id:"n2",type:"check",question:"5×(-5)を計算すると？",choices:["-25","25","10"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"正の数×負の数は負の数になる決まりだよ。5×(-5)=-25だね。",next:"n2"},{id:"n3",type:"explain",text:"5×(-5)=-25。だから式は-3-(-25)になったね。ここが最大の注意点。『マイナスを引く』は『足す』に直すんだったね。",next:"n4"},{id:"n4",type:"check",question:"-3-(-25)を減法から加法に直すとどれ？",choices:["-3-25","-3+25","3+25"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"『負の数を引く』のは『その数を足す』のと同じだったね。-3-(-25)は-3+25に直せる。符号処理を忘れて-3-25としないように注意しよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。負×負は正になり、負の数を引く形は足し算に直す。-3-5×(-5)=-3-(-25)=-3+25=22が正解だよ。",next:"end"}]}},{id:"P0-MOJI-108",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"y=-6のとき 18/y の値。",answer:"-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"18/yにy=-6を代入するよ。かっこをつけて代入すると18÷(-6)になる。わり算にも符号のルールがあるから気をつけよう。",next:"n2"},{id:"n2",type:"check",question:"正の数÷負の数の答えの符号はどっち？",choices:["正の符号","負の符号","符号は気にしなくてよい"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"わり算も、かけ算と同じ符号のルールが使えるよ。正の数÷負の数は負の数になる。符号を『気にしなくていい』は間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"18÷(-6)の答えの符号は負だと分かったね。あとは絶対値どうしのわり算18÷6を計算しよう。",next:"n4"},{id:"n4",type:"check",question:"18÷6を計算すると？",choices:["3","6","2"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"18÷6は普通のわり算だよ。18を6でわると3になる。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。絶対値の計算18÷6=3に、正÷負で決まる負の符号をつけて、18÷(-6)=-3が正解だよ。",next:"end"}]}},{id:"P0-MOJI-109",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=4のとき 3x² の値。",answer:"48",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3x²にx=4を代入すると3×4²になるよ。ここでのポイントは²（2乗）の意味と、計算の順序だ。",next:"n2"},{id:"n2",type:"check",question:"4²はどういう意味？",choices:["4を2倍する（4×2）","4を2回かける（4×4）","4に2を足す（4+2）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"²（2乗）は『同じ数を2回かける』という意味だよ。4²は4×4=16のことで、4×2=8（2倍）ではないよ。",next:"n2"},{id:"n3",type:"explain",text:"4²=4×4=16だと分かったね。次に計算の順序。累乗はかけ算より先に計算するので、3×4²ではまず4²を計算する。",next:"n4"},{id:"n4",type:"check",question:"3×4²を正しく計算する順番はどれ？",choices:["先に3×4=12を計算してから2乗する","先に4²=16を計算してから3をかける","順番はどちらでもよい"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"累乗（²）は、かけ算より先に計算する決まりだよ。3×4=12を先に計算してしまうと、正しい答えにならないんだ。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。²は『2回かける』という意味で、累乗はかけ算より先に計算する。4²=16を先に求めてから3をかけて、3×16=48が正解だよ。",next:"end"}]}},{id:"P0-MOJI-110",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=6のとき -x² の値。",answer:"-36",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-x²にx=6を代入するよ。ここで一番大事なのは、『-x²』の中で2乗されるのはxだけで、マイナスは2乗の外にあるということ。",next:"n2"},{id:"n2",type:"check",question:"-x²にx=6を正しく代入するとどれ？",choices:["-(6²)","(-6)²","-6×2"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-x²は『-(x²)』という意味で、マイナスはx²の外についているんだ。xを代入するときにマイナスも一緒にかっこの中に入れて(-6)²としてしまうのはよくある間違いだよ。",next:"n2"},{id:"n3",type:"explain",text:"-(6²)の形になったね。まず6²を計算しよう。6×6だよ。",next:"n4"},{id:"n4",type:"check",question:"6²=36。最後に-(36)を計算すると？",choices:["-36","36","-12"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-(36)は36に負の符号をつけるだけだから-36になるよ。²を2倍と勘違いしたり、かっこの位置を間違えたりしないように気をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。-x²は2乗されるのはxだけで、符号は最後につく。-(6²)=-(36)=-36が正解だよ。",next:"end"}]}},{id:"P0-MOJI-111",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=-3のとき 5x² の値。",answer:"45",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5x²にx=-3を代入するよ。負の数を累乗の中に代入するときは、必ずかっこをつける決まりだ。x² → (-3)²のようにね。",next:"n2"},{id:"n2",type:"check",question:"x=-3をx²に正しく代入するとどれ？",choices:["(-3)²","-3²","-3×2"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこをつけずに-3²と書くと、マイナスがつかない3だけが2乗される意味になってしまうよ。負の数x=-3を2乗するときは、必ず(-3)とかっこをつけてから²をつけよう。",next:"n2"},{id:"n3",type:"explain",text:"(-3)²の形になったね。(-3)×(-3)を計算しよう。負×負は正になるよ。",next:"n4"},{id:"n4",type:"check",question:"(-3)²=9。最後に5×9を計算すると？",choices:["45","-45","-30"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5×9は普通のかけ算だよ。5に9をかけると45になる。係数5をかけ忘れないように気をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。負の数を累乗に代入するときは必ずかっこをつける。5×(-3)²=5×9=45が正解だよ。",next:"end"}]}},{id:"P0-MOJI-112",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=1/4のとき 8+4x の値。",answer:"9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"8+4xにx=1/4を代入すると、8+4×(1/4)になるよ。ここでのポイントは『どの順番で計算するか』だ。",next:"n2"},{id:"n2",type:"check",question:"8+4×(1/4)では、たし算とかけ算、どちらを先に計算する？",choices:["たし算の8+4を先に計算する","かけ算の4×(1/4)を先に計算する","どちらからでもよい"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"計算の決まりでは、かけ算・わり算はたし算・ひき算より先に計算するんだったね。分数が入っていても同じ。だから8+4×(1/4)では、先に4×(1/4)を計算するよ。",next:"n2"},{id:"n3",type:"explain",text:"4×(1/4)を計算しよう。4に1/4をかけると、分母の4と約分できて1になるよ。",next:"n4"},{id:"n4",type:"check",question:"8+1を計算すると？",choices:["9","3","8.25"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"8+1は普通のたし算だよ。8に1を足すと9になる。先に8+4=12を計算して1/4をかけたり、かけ算をせず1/4をそのまま足したりしないように気をつけよう。",next:"n4"},{id:"n5",type:"explain",text:"まとめ。代入したら8+4×(1/4)の形になり、かけ算を先に計算する。8+4×(1/4)=8+1=9が正解だよ。",next:"end"}]}},{id:"P0-MOJI-113",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=4のとき 3x²+5 の値を求めなさい。",answer:"53",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"式の値を求める問題では、xに数を代入してから計算のルール通りに計算します。3x²+5にx=4を代入すると 3×4²+5 になります。",next:"n2"},{id:"n2",type:"check",question:"3×4²+5 を計算するとき、最初に計算するのはどこですか？",choices:["3×4の部分","4²の部分"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"累乗（２乗）はかけ算より先に計算する決まりがあります。3×4²は「3×(4×4)」という意味なので、まず4²を計算します。",next:"n2"},{id:"n3",type:"explain",text:"4²=4×4=16 です。これは「4を2倍する（4×2=8）」とは全く違う計算なので混同しないようにしましょう。",next:"n4"},{id:"n4",type:"check",question:"4²=16を使うと、3×4²+5はどんな式になりますか？",choices:["3×4+5","3×16+5"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"4²の計算結果である16をそのまま式に入れます。3×16+5という式になります。",next:"n4"},{id:"n5",type:"explain",text:"3×16+5 を計算します。3×16=48、48+5=53。よって答えは53です。累乗を先に計算する順序さえ守れば、あとは普通の四則計算です。",next:"end"}]}},{id:"P0-MOJI-114",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=4のとき x²+2x の値を求めなさい。",answer:"24",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"x²+2xにx=4を代入すると 4²+2×4 という式になります。x²の項と2xの項は文字の形が違うので、別々に計算する必要があります。",next:"n2"},{id:"n2",type:"check",question:"4²+2×4 を計算するとき、正しい進め方はどちらですか？",choices:["4²と2×4を別々に計算してから足す","4と2と4をすべてかけ合わせる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"x²と2xは同類項ではないため、数字をまとめてかけてしまうことはできません。それぞれの項を別々に計算してから、最後に足し算でまとめます。",next:"n2"},{id:"n3",type:"explain",text:"4²=4×4=16です。これは2xの計算とは全く別のものなので、混同しないようにしましょう。",next:"n4"},{id:"n4",type:"check",question:"2×4はいくつですか？",choices:["6","8"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2×4は「2を4回」または「4を2回」足したものです。落ち着いて計算すると8になります。",next:"n4"},{id:"n5",type:"explain",text:"16と8が求まったので、最後に足し算します。16+8=24。よって答えは24です。",next:"end"}]}},{id:"P0-MOJI-115",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=-3,y=4のとき 5x+2y の値を求めなさい。",answer:"-7",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5x+2yにx=-3, y=4を代入します。負の数を代入するときは、必ずカッコで包みます。5×(-3)+2×4 という式になります。",next:"n2"},{id:"n2",type:"check",question:"5×(-3) の計算結果はどれですか？",choices:["15（プラス）","-15（マイナス）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"正の数×負の数はマイナスになります。カッコを付けずに計算すると符号を見失いやすいので、5×(-3)と丁寧に書いて計算しましょう。",next:"n2"},{id:"n3",type:"explain",text:"5×(-3)=-15です。次に2×4を計算します。こちらは両方正の数なので8になります。",next:"n4"},{id:"n4",type:"check",question:"-15+8 の計算結果はどれですか？",choices:["-7","-23"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-15に8を足すので、引き算にしてはいけません。-15+8は、-15から8だけ0に近づくので-7になります。",next:"n4"},{id:"n5",type:"explain",text:"-15+8=-7。よって答えは-7です。負の数の代入はカッコを忘れず、符号の計算を1つずつ確認することが大切です。",next:"end"}]}},{id:"P0-MOJI-116",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=-3,y=4のとき -4xy の値を求めなさい。",answer:"48",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-4xyにx=-3, y=4を代入します。負の数xは必ずカッコで包みます。-4×(-3)×4 という式になります。",next:"n2"},{id:"n2",type:"check",question:"-4×(-3) の計算結果の符号はどちらですか？",choices:["プラス","マイナス"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナス×マイナスはプラスになります。カッコを付けずに計算すると符号を見失いやすいので、-4×(-3)と丁寧に書いて確認しましょう。",next:"n2"},{id:"n3",type:"explain",text:"-4×(-3)=12です。マイナスが2個あるのでプラスになりました。",next:"n4"},{id:"n4",type:"check",question:"12×4 の計算結果はどれですか？",choices:["48","12"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"12に最後のy（=4）をかけるのを忘れないようにしましょう。12×4を計算します。",next:"n4"},{id:"n5",type:"explain",text:"12×4=48。よって答えは48です。マイナスの個数を数えて符号を先に決めてから計算すると間違えにくくなります。",next:"end"}]}},{id:"P0-MOJI-117",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=4,y=-3のとき -3x-2y の値を求めなさい。",answer:"-6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-3x-2yにx=4, y=-3を代入します。負の数yは必ずカッコで包みます。-3×4-2×(-3) という式になります。",next:"n2"},{id:"n2",type:"check",question:"-2×(-3) の計算結果の符号はどちらですか？",choices:["プラス","マイナス"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナス×マイナスはプラスになります。マイナスが並んでいるからといって全部引き算にはなりません。1つずつ符号を確認しましょう。",next:"n2"},{id:"n3",type:"explain",text:"-2×(-3)=6です。また、-3×4=-12です。この2つの項を最後に足し合わせます。",next:"n4"},{id:"n4",type:"check",question:"-12+6 の計算結果はどれですか？",choices:["-6","-18"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-12に6を足すので、引き算にしてはいけません。-12+6は、-12から6だけ0に近づくので-6になります。",next:"n4"},{id:"n5",type:"explain",text:"-12+6=-6。よって答えは-6です。マイナスが多く並んでいても、1つずつ項の符号を確認すれば間違えません。",next:"end"}]}},{id:"P0-MOJI-118",subunit:"式の値（代入）",difficulty:"★2標準",problem_text:"x=4,y=-3のとき 3x+3y の値を求めなさい。",answer:"3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3x+3yにx=4, y=-3を代入します。負の数yは必ずカッコで包みます。3×4+3×(-3) という式になります。",next:"n2"},{id:"n2",type:"check",question:"3xと3yは、係数がどちらも3ですが、まとめて計算してよいですか？",choices:["よい（6xyにまとめられる）","よくない（xとyは別の文字だから別々に計算）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数が同じでも、xとyは別の文字なので同類項ではありません。それぞれ別々に代入して計算する必要があります。",next:"n2"},{id:"n3",type:"explain",text:"3×4=12、3×(-3)=-9をそれぞれ計算します。",next:"n4"},{id:"n4",type:"check",question:"12+(-9) の計算結果はどれですか？",choices:["3","21"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"3×(-3)はマイナスのままです。プラスに変えてしまわないよう注意し、12+(-9)を計算しましょう。",next:"n4"},{id:"n5",type:"explain",text:"12+(-9)=3。よって答えは3です。係数が同じでも文字が違えばまとめず、別々に代入することが大切です。",next:"end"}]}},{id:"P0-MOJI-119",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=-3のとき -x³ の値を求めなさい。",answer:"27",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-x³にx=-3を代入します。負の数xは必ずカッコで包みます。-(-3)³ という式になります。式の先頭のマイナスとカッコの中の(-3)は別のものとして扱います。",next:"n2"},{id:"n2",type:"check",question:"(-3)³ の符号はどちらになりますか？",choices:["プラス","マイナス"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナスを奇数回（3回）かけるとマイナスのままです。(-3)×(-3)×(-3)を順番に計算して確認しましょう。",next:"n2"},{id:"n3",type:"explain",text:"(-3)³=(-3)×(-3)×(-3)=-27です。カッコの中の計算はここまでです。",next:"n4"},{id:"n4",type:"check",question:"式の先頭についているマイナスを-27にかけると、どうなりますか？",choices:["-27のまま","27（プラスになる）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"式の先頭のマイナスをかけ忘れないようにしましょう。-(-27)は、マイナス×マイナスと同じ考え方でプラスになります。",next:"n4"},{id:"n5",type:"explain",text:"-(-27)=27。よって答えは27です。負の数の代入はカッコで包み、式の先頭の符号も忘れずに最後までかけることが大切です。",next:"end"}]}},{id:"P0-MOJI-120",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=1/4のとき 16x² の値を求めなさい。",answer:"1",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"16x²にx=1/4を代入します。16×(1/4)² という式になります。まず(1/4)²の部分を先に計算します。",next:"n2"},{id:"n2",type:"check",question:"(1/4)² の正しい計算方法はどちらですか？",choices:["1/4を2倍する（1/4×2）","分子と分母をそれぞれ2乗する（1²/4²）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数の2乗は「2倍」ではありません。(1/4)²は(1/4)×(1/4)という意味なので、分子どうし・分母どうしをかけます。",next:"n2"},{id:"n3",type:"explain",text:"(1/4)²=1²/4²=1/16です。これを元の式に戻すと16×1/16となります。",next:"n4"},{id:"n4",type:"check",question:"16×1/16 を計算するとどうなりますか？",choices:["1","4"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"16と16は同じ数なので、約分するとすべて消えて1になります。16÷16=1と考えましょう。",next:"n4"},{id:"n5",type:"explain",text:"16×1/16=1。よって答えは1です。分数の累乗は分子・分母をそれぞれ2乗することが大切です。",next:"end"}]}},{id:"P0-MOJI-121",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"a=-4,b=1のとき 3/4 a+b の値を求めなさい。",answer:"-2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3/4a+bにa=-4, b=1を代入します。負の数aは必ずカッコで包みます。3/4×(-4)+1 という式になります。",next:"n2"},{id:"n2",type:"check",question:"3/4×(-4) の計算結果はどれですか？",choices:["-3","3"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数×負の数の符号はマイナスになります。カッコを付けずに計算すると符号を見失いやすいので、3/4×(-4)と丁寧に書いて確認しましょう。",next:"n2"},{id:"n3",type:"explain",text:"3/4×(-4)=-3です。次に、bの項である+1を忘れずに足します。",next:"n4"},{id:"n4",type:"check",question:"-3+1 の計算結果はどれですか？",choices:["-2","-4"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-3に1を足すので、引き算にしてはいけません。-3+1は、-3から1だけ0に近づくので-2になります。",next:"n4"},{id:"n5",type:"explain",text:"-3+1=-2。よって答えは-2です。分数と負の数が同時に出てきても、1つずつ丁寧に計算すれば間違えません。",next:"end"}]}},{id:"P0-MOJI-122",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"a=-4,b=3のとき -7/12 ab の値を求めなさい。",answer:"7",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-7/12ab にa=-4, b=3を代入します。負の数aは必ずカッコで包みます。-7/12×(-4)×3 という式になります。",next:"n2"},{id:"n2",type:"check",question:"-7/12×(-4) の計算結果の符号はどちらですか？",choices:["プラス","マイナス"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナス×マイナスはプラスになります。カッコを付けずに計算すると符号を見失いやすいので、-7/12×(-4)と丁寧に書いて確認しましょう。",next:"n2"},{id:"n3",type:"explain",text:"-7/12×(-4)を約分すると7/3になります。まだbの3をかける計算が残っています。",next:"n4"},{id:"n4",type:"check",question:"7/3×3 の計算結果はどれですか？",choices:["7","7/3のまま"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"bの3をかけ忘れないようにしましょう。7/3×3を計算すると分母の3が消えます。",next:"n4"},{id:"n5",type:"explain",text:"7/3×3=7。よって答えは7です。分数の約分と符号を1つずつ確認しながら計算することが大切です。",next:"end"}]}},{id:"P0-MOJI-123",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=4,y=-3のとき -x²+2y² の値を求めなさい。",answer:"2",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-x²+2y²にx=4, y=-3を代入します。xは正の数なのでカッコは不要で-4²、yは負の数なのでカッコで包み2×(-3)²とします。",next:"n2"},{id:"n2",type:"check",question:"-4² の計算結果はどれですか？",choices:["-16","16"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"-4²は「4²の前にマイナスがつく」という意味で、(-4)²とは違います。まず4²=16を計算し、その後マイナスをつけて-16とします。",next:"n2"},{id:"n3",type:"explain",text:"-4²=-16です。次に2y²、つまり2×(-3)²を計算します。yは負の数なのでカッコで包みます。",next:"n4"},{id:"n4",type:"check",question:"2×(-3)² の計算結果はどれですか？",choices:["18","-18"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"(-3)²はマイナス×マイナスでプラス9になります。2×9=18で、これはプラスの値です。",next:"n4"},{id:"n5",type:"explain",text:"-16+18=2。よって答えは2です。どの項にカッコが必要かを1つずつ確認することが、この問題の一番のポイントです。",next:"end"}]}},{id:"P0-MOJI-124",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=4,y=-3のとき 3xy² の値を求めなさい。",answer:"108",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3xy²にx=4, y=-3を代入します。負の数yは必ずカッコで包みます。3×4×(-3)² という式になります。",next:"n2"},{id:"n2",type:"check",question:"(-3)² の計算結果の符号はどちらですか？",choices:["プラス","マイナス"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"マイナス×マイナスはプラスになります。カッコを付けずに-3²と書くと符号を間違えやすいので注意しましょう。",next:"n2"},{id:"n3",type:"explain",text:"(-3)²=9です。yの符号がマイナスでも、2乗した結果はプラスになることを覚えておきましょう。",next:"n4"},{id:"n4",type:"check",question:"3×4×9 の計算結果はどれですか？",choices:["108","-108"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"(-3)²=9はプラスの値です。元のyがマイナスだったからといって、答えにマイナスをつけてしまわないようにしましょう。",next:"n4"},{id:"n5",type:"explain",text:"3×4×9=108。よって答えは108です。負の数を2乗する項は必ずカッコをつけてから計算することが大切です。",next:"end"}]}},{id:"P0-MOJI-125",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=4,y=-3のとき (3x-y)/5 の値を求めなさい。",answer:"3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(3x-y)/5にx=4, y=-3を代入します。負の数yは必ずカッコで包みます。(3×4-(-3))/5 という式になります。",next:"n2"},{id:"n2",type:"check",question:"12-(-3) の計算結果はどれですか？",choices:["9（引き算のまま）","15（足し算に変わる）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"引く数が負の数のときは、符号が変わって足し算になります。12-(-3)は12+3と同じ意味なので15になります。",next:"n2"},{id:"n3",type:"explain",text:"3×4-(-3)=15です。これが分子の値になります。あとは分母の5で割るだけです。",next:"n4"},{id:"n4",type:"check",question:"15/5 の計算結果はどれですか？",choices:["3","9/5"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"分子は12-(-3)=15であり、9ではありません。15を5で割って計算しましょう。",next:"n4"},{id:"n5",type:"explain",text:"15/5=3。よって答えは3です。引く数が負の数のときに符号が変わることを忘れずに、分子を正しく求めることが大切です。",next:"end"}]}},{id:"P0-MOJI-126",subunit:"式の値（代入）",difficulty:"★3応用",problem_text:"x=4,y=-3のとき -1/4 x²-1/3 y の値を求めなさい。",answer:"-3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-1/4x²-1/3yにx=4, y=-3を代入します。負の数yは必ずカッコで包みます。-1/4×4²-1/3×(-3) という式になります。",next:"n2"},{id:"n2",type:"check",question:"-1/4×4² の計算結果はどれですか？",choices:["-4","4"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"まず4²=16を計算し、それに-1/4をかけます。-1/4×16はマイナスの値になります。",next:"n2"},{id:"n3",type:"explain",text:"-1/4×16=-4です。次に-1/3×(-3)を計算します。マイナス×マイナスなのでプラスになります。",next:"n4"},{id:"n4",type:"check",question:"-1/3×(-3) の計算結果はどれですか？",choices:["1","-1"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"マイナス×マイナスはプラスになります。カッコを付けずに計算すると符号を見失いやすいので、-1/3×(-3)と丁寧に確認しましょう。",next:"n4"},{id:"n5",type:"explain",text:"-4+1=-3。よって答えは-3です。分数の係数が2つあっても、項ごとに符号込みで計算することが大切です。",next:"end"}]}},{id:"P0-MOJI-127",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"縦acm・横bcmの長方形の花だんがある。2a+2bは何を表すか（単位も含めて答えなさい）。",answer:"長方形の周の長さ（cm）",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"式が何を表すかを読み取るときは、公式の形と見比べます。長方形の周の長さの公式は「（縦＋横）×2」です。",next:"n2"},{id:"n2",type:"check",question:"(a+b)×2 を分配法則で展開すると、どんな式になりますか？",choices:["2a+2b","ab"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分配法則では、カッコの外の2をカッコの中のaとbの両方にかけます。2×a+2×b=2a+2bとなります。",next:"n2"},{id:"n3",type:"explain",text:"(a+b)×2を展開すると2a+2bになりました。これは問題の式と同じ形です。つまり2a+2bは周の長さを表しています。",next:"n4"},{id:"n4",type:"check",question:"2a+2bが表す量の単位はどちらですか？",choices:["cm（長さ）","cm²（面積）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"2a+2bにはa×bのような文字どうしのかけ算が含まれていません。長さを2倍して足しただけなので、単位は面積のcm²ではなくcmです。",next:"n4"},{id:"n5",type:"explain",text:"2a+2bは長方形の周の長さ（cm）を表します。式の形を公式と見比べ、単位も長さか面積かを確認することが大切です。",next:"end"}]}},{id:"P0-MOJI-128",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"同上の縦acm・横bcmの長方形の花だんについて、abは何を表すか（単位も含めて答えなさい）。",answer:"長方形の面積（cm²）",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"式が何を表すかを読み取るときは、公式の形と見比べます。長方形の面積の公式は「縦×横」です。",next:"n2"},{id:"n2",type:"check",question:"a×b をabと表したとき、これはどの公式と同じ形ですか？",choices:["面積（縦×横）","周の長さ（（縦+横）×2）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"周の長さの公式は足し算とかけ算が混ざった（縦+横）×2という形でした。abは足し算を含まない単純なかけ算なので、面積の公式と同じ形です。",next:"n2"},{id:"n3",type:"explain",text:"a×b=abは縦×横と同じ形なので、abは面積を表しています。前の問題の2a+2b（周の長さ）とは式の形が違うことを確認しましょう。",next:"n4"},{id:"n4",type:"check",question:"abが表す量の単位はどちらですか？",choices:["cm（長さ）","cm²（面積）"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"abはa×b、つまり長さ×長さのかけ算です。長さ×長さの単位はcm²（面積）になります。",next:"n4"},{id:"n5",type:"explain",text:"abは長方形の面積（cm²）を表します。前の問題の周の長さと混同しないよう、式の形（足し算かかけ算か）に注目することが大切です。",next:"end"}]}},{id:"P0-MOJI-129",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"動物園の入園料がおとなp円、こどもq円のとき、5p+2q は何を表すか。",answer:"おとな5人とこども2人の入園料の和",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5p+2qのpとqは、それぞれ「おとな1人分」「こども1人分」の料金を表す文字です。まず係数の意味を確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"5pは何を表しますか？",choices:["おとな5人分の料金","おとなとこども合わせて5人分"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"5pは「p（おとな1人分の料金）」が5個ぶんという意味です。5と2をいきなり足してはいけません。",next:"n2"},{id:"n3",type:"check",question:"2qは何を表しますか？",choices:["こども2人分の料金","こども5人分の料金"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"2qは「q（こども1人分の料金）」が2個ぶんです。5とpの対応、2とqの対応を混同しないようにしましょう。",next:"n3"},{id:"n4",type:"explain",text:"5p+2qは「おとな5人分の料金」と「こども2人分の料金」をたした式なので、「おとな5人とこども2人の入園料の和」を表します。",next:"end"}]}},{id:"P0-MOJI-130",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"同上で p-q は何を表すか。",answer:"おとな1人とこども1人の入園料の差",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"p-qは、pとqという2つの量のあいだに「-」がある式です。まず「-」が何を表す記号か確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"式の中の「-」はどんな演算を表しますか？",choices:["引き算（差）","たし算（和）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「出てきた数はいつも足す」わけではありません。式に書かれている記号がそのまま演算を表します。「-」は引き算です。",next:"n2"},{id:"n3",type:"explain",text:"p-qはpからqを引く式なので、「おとな1人分の料金からこども1人分の料金を引いたもの」、つまり2つの金額の差を表します。",next:"end"}]}},{id:"P0-MOJI-131",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"横にs人ずつt列並ぶとき、4s は何を表すか。",answer:"4列分の人数",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この場面ではsは「1列あたりの人数」、tは「列の数」を表す文字です。まずsの意味を確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"sは何を表す文字ですか？",choices:["1列あたりの人数","列の数"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"sは「1列あたりの人数」を表す文字です。4sの4は「人数」ではなく「何列分か」を表す数です。",next:"n2"},{id:"n3",type:"explain",text:"4sはsを4個分たしたもの、つまりsの4倍です。sが1列あたりの人数なので、4sは「4列分の人数」を表します。",next:"end"}]}},{id:"P0-MOJI-132",subunit:"式の意味を読む",difficulty:"★2標準",problem_text:"同上で st は何を表すか。",answer:"全体の人数",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字を並べて書くst のような形は、s×tのかけ算を表す約束でした。まずこの約束を確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"stはどんな演算を表しますか？",choices:["s×t（かけ算）","s+t（たし算）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字を並べて書く形は、常にかけ算を表します。「文字が並んでいるからたし算」ではありません。",next:"n2"},{id:"n3",type:"explain",text:"stはs×t、つまり「1列あたりの人数×列の数」を表すので、全体の人数を表します。",next:"end"}]}},{id:"P0-MOJI-133",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"pとqの和を5倍した数を式で表しなさい。",answer:"5(p+q)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「pとqの和」はp+qです。まずこの部分を確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"「5倍」は何にかかりますか？",choices:["p+q全体","pだけ"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「和を5倍」なので、5はp+q全体にかかります。pだけにかけると意味が変わってしまいます。",next:"n2"},{id:"n3",type:"explain",text:"p+q全体を5倍するには、かっこでくくって5(p+q)と書きます。数字を後ろに書いたり、5をpだけにかけたりしないよう注意しましょう。",next:"end"}]}},{id:"P0-MOJI-134",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"1本120円のペンx本と1個70円の消しゴムy個の代金の合計を式で表しなさい。",answer:"(120x+70y)円",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"代金は「単価×個数」で求めます。ペンと消しゴムそれぞれの代金を別々に考えましょう。",next:"n2"},{id:"n2",type:"check",question:"ペンx本の代金はどう表しますか？",choices:["120x円","120+x円"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"代金は単価×個数なので、たし算ではなくかけ算です。120×x=120xとなります。",next:"n2"},{id:"n3",type:"check",question:"120xと70yはひとつの項にまとめられますか？",choices:["まとめられない（文字が違うため）","190xyにまとめられる"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"xとyは違う文字なので、係数どうし・文字どうしを勝手にかけ合わせてまとめることはできません。",next:"n3"},{id:"n4",type:"explain",text:"ペンの代金120xと消しゴムの代金70yはそのままたして、合計は120x+70y円となります。",next:"end"}]}},{id:"P0-MOJI-135",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"y円のりんごを6個買い2000円札で払ったときのおつりを式で表しなさい。",answer:"(2000-6y)円",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"おつりは「支払った金額－代金」で求めます。まずりんご6個の代金を求めましょう。",next:"n2"},{id:"n2",type:"check",question:"りんご6個の代金はどう表しますか？",choices:["6y円","y6円"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"単価×個数なので、y×6=6yと表します。数字を前に書く約束でしたね。",next:"n2"},{id:"n3",type:"check",question:"おつりを求める式の順番は？",choices:["2000-6y（支払い額から代金を引く）","6y-2000（代金から支払い額を引く）"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"おつりは「支払った金額－代金」の順です。逆にすると意味が変わってしまいます。",next:"n3"},{id:"n4",type:"explain",text:"支払った2000円から代金6yを引いて、おつりは2000-6y円になります。",next:"end"}]}},{id:"P0-MOJI-136",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"時速45kmでy時間進んだ道のりを式で表しなさい。",answer:"45y km",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"道のりは「速さ×時間」で求めます。速さは時速45km、時間はy時間です。",next:"n2"},{id:"n2",type:"check",question:"道のりを求める式はどれですか？",choices:["45×y","45+y"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"道のり＝速さ×時間なので、かけ算です。たし算ではありません。",next:"n2"},{id:"n3",type:"explain",text:"45×yを文字式のルールにそって書くと、数字を前に、×を省いて45ykmになります。y45とは書きません。",next:"end"}]}},{id:"P0-MOJI-137",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"y人の65％を式で表しなさい。",answer:"0.65y 人",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"「y人の65％」を求めるには、まず65％を小数に直す必要があります。",next:"n2"},{id:"n2",type:"check",question:"65％を小数で表すといくつですか？",choices:["0.65","65"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"百分率（％）は100で割って小数に直します。65％は65÷100=0.65です。65のまま使ってはいけません。",next:"n2"},{id:"n3",type:"explain",text:"0.65とyをかけ算して、y人の65％は0.65y人と表します。",next:"end"}]}},{id:"P0-MOJI-138",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"1個y円のオレンジを7個買ったときの代金を式で表しなさい。",answer:"7y 円",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"代金は「単価×個数」で求めます。単価はy円、個数は7個です。",next:"n2"},{id:"n2",type:"check",question:"代金を求める式はどれですか？",choices:["y×7","y+7"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"代金＝単価×個数なので、かけ算です。たし算ではありません。",next:"n2"},{id:"n3",type:"explain",text:"y×7を文字式のルールにそって書くと、数字を前に出して7y円になります。y7とは書きません。",next:"end"}]}},{id:"P0-MOJI-139",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"1冊220ページのノートをyページ目まで書いたときの残りページ数を式で表しなさい。",answer:"(220-y)ページ",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"残りのページ数は「全体のページ数－使ったページ数」で求めます。全体は220ページ、使った分はyページです。",next:"n2"},{id:"n2",type:"check",question:"残りページ数を求める式の順番は？",choices:["220-y（全体から使った分を引く）","y-220（使った分から全体を引く）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"残りは「全体－使った分」の順です。逆にすると意味が変わってしまいます。",next:"n2"},{id:"n3",type:"explain",text:"全体220ページから使った分yページを引いて、残りは220-yページになります。",next:"end"}]}},{id:"P0-MOJI-140",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"姉の年齢をy歳とするとき、4歳年下の妹の年齢を式で表しなさい。",answer:"(y-4)歳",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"妹は姉より4歳年下です。姉の年齢はy歳です。「年下」がどんな演算になるか確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"「4歳年下」はどんな式になりますか？",choices:["y-4（引き算）","y+4（たし算）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「年下」は年齢が小さいことを表すので、引き算です。「4歳ちがう」からといって足すとは限りません。",next:"n2"},{id:"n3",type:"explain",text:"姉の年齢yから4を引いて、妹の年齢はy-4歳になります。",next:"end"}]}},{id:"P0-MOJI-141",subunit:"数量を文字式で表す",difficulty:"★1基礎",problem_text:"長さycmのテープを3等分したときの1本の長さを式で表しなさい。",answer:"y/3 cm",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"全体を等分するときは、全体の長さを等分数で割ります。ycmを3等分するのでy÷3です。",next:"n2"},{id:"n2",type:"check",question:"文字式でy÷3はどう表しますか？",choices:["y/3（分数）","y3（数字をそのまま並べる）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷の記号を消すだけではいけません。除法は分数の形で表す約束です。",next:"n2"},{id:"n3",type:"explain",text:"y÷3は分数で表してy/3cmとなります。これが1本の長さです。",next:"end"}]}},{id:"P0-MOJI-142",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"9でわると商がb、あまりが4となる数を式で表しなさい。",answer:"9b+4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"わり算の関係は「わる数×商＋あまり＝もとの数」です。わる数は9、商はb、あまりは4です。",next:"n2"},{id:"n2",type:"check",question:"9×bはどう表しますか？",choices:["9b","b9"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字式では数字を文字の前に書く約束です。b×9でも9bと書きます。",next:"n2"},{id:"n3",type:"explain",text:"9bにあまりの4をたして、もとの数は9b+4と表します。4bのように、あまりを係数の位置に置かないよう注意しましょう。",next:"end"}]}},{id:"P0-MOJI-143",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"pkmを時速3km、qkmを時速6kmで歩いたときの合計時間を式で表しなさい。",answer:"(p/3 + q/6)時間",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"時間は「道のり÷速さ」で求めます。pkmは時速3km、qkmは時速6kmで歩きました。",next:"n2"},{id:"n2",type:"check",question:"pkmを時速3kmで歩いたときの時間はどう表しますか？",choices:["p/3時間","p/6時間"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"pkmを歩いたときの速さは時速3kmです。対応する数字を取り違えないようにしましょう。",next:"n2"},{id:"n3",type:"check",question:"p/3とq/6をたすとき、分母の3と6はどうなりますか？",choices:["そのままたし算する（分母はまとめない）","3+6=9として1つの分数にする"],correct:0,onCorrect:"n4",onWrong:"n3r"},{id:"n3r",type:"explain",text:"分母が違う分数の分母どうしをたして1つにまとめることはできません。それぞれの時間をそのままたし算します。",next:"n3"},{id:"n4",type:"explain",text:"p/3の時間とq/6の時間をたして、合計時間はp/3+q/6時間になります。",next:"end"}]}},{id:"P0-MOJI-144",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"p円の商品を2割引きにした値段を式で表しなさい。",answer:"0.8p 円",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2割引きは、定価の(1-0.2)倍の値段になります。まず1-0.2を計算しましょう。",next:"n2"},{id:"n2",type:"check",question:"1-0.2はいくつですか？",choices:["0.8","0.2"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"2割引きは定価の80%の値段になるということです。0.2は「引かれる割合」であり、そのまま値段にかけると値引き額になってしまいます。",next:"n2"},{id:"n3",type:"explain",text:"0.8×p=0.8pが、2割引き後の値段になります。",next:"end"}]}},{id:"P0-MOJI-145",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"xLの牛乳のパックと400mLの牛乳のパックがある。この2つを合わせた量を[mL]で表しなさい。",answer:"(1000x+400)mL",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この問題は「xL」と「400mL」という違う単位の量を1つの式にまとめる問題です。単位がそろっていないと、そのまま足すことはできません。",next:"n2"},{id:"n2",type:"check",question:"1L は何mLでしょう？",choices:["100mL","1000mL"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1L=1000mLです。この関係を使ってxLをmLに直します。",next:"n2"},{id:"n3",type:"explain",text:"xL=1000x mL となります。これは「x+400mL」のようにxをそのまま使ってはいけない、というポイントです。",next:"n4"},{id:"n4",type:"check",question:"1000x mL と 400mL を合わせた量はどう表す？",choices:["(1000x+400)mL","(x+400)mL"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"xはすでに1000x mLに変換済みです。変換前のxをそのまま使ってしまうと、単位のそろっていない足し算になってしまいます。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：単位が異なる数量を1つの式にするときは、先に単位をそろえてから演算する。今回は (1000x+400)mL が正解です。",next:"end"}]}},{id:"P0-MOJI-146",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"長さ2mのテープからbcmのテープを3本切り取ったときの残りの長さを[cm]で表しなさい。",answer:"(200-3b)cm",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この問題は「2m」と「bcm」という単位の違う量を扱い、さらに「3本切り取る」という個数の情報も式にする必要があります。",next:"n2"},{id:"n2",type:"check",question:"2mはcmに直すと何cm？",choices:["20cm","200cm"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1m=100cmなので、2m=200cmです。",next:"n2"},{id:"n3",type:"explain",text:"次に、bcmのテープを3本切り取る長さを考えます。数と文字の積は、数を文字の前に書いて×を省略します。",next:"n4"},{id:"n4",type:"check",question:"bcmを3本切り取った長さの表し方は？",choices:["b3cm","3bcm"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字式では数を文字の前に書きます。b×3は3bと表します。b3では意味が伝わりません。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：全体200cmから切り取った3b cmを引いて (200-3b)cm。単位変換と「数を前に書く」ルールの両方が必要でした。",next:"end"}]}},{id:"P0-MOJI-147",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"長さxmのリボン1本とycmのリボン4本を合わせた長さを[cm]で表しなさい。",answer:"(100x+4y)cm",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"xmとycmという単位の違う長さを合わせ、さらに「4本」という個数の情報も式に入れる必要があります。",next:"n2"},{id:"n2",type:"check",question:"xmはcmに直すとどう表せる？",choices:["x cm","100x cm"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1m=100cmなので、xm=100x cmです。",next:"n2"},{id:"n3",type:"explain",text:"次に、ycmのリボン4本分の長さを考えます。数と文字の積は数を前に書きます。",next:"n4"},{id:"n4",type:"check",question:"ycmを4本分にした長さの表し方は？",choices:["y4cm","4ycm"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字式では数を文字の前に書きます。y×4は4yと表します。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：100x cmと4y cmを足して (100x+4y)cm。単位変換と「数を前に書く」ルールの両方が必要でした。",next:"end"}]}},{id:"P0-MOJI-148",subunit:"数量を文字式で表す",difficulty:"★2標準",problem_text:"あめをc人に4個ずつ配るとd個余るとき、はじめにあったあめの個数を式で表しなさい。",answer:"(4c+d)個",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この問題は「4個ずつc人に配る」という単位あたり量×人数の関係と、「d個余る」という加える関係の2つを式にします。",next:"n2"},{id:"n2",type:"check",question:"c人に4個ずつ配った個数はどう表す？",choices:["4+c","4c"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「4個ずつc人分」は4×cという積の関係です。4+cのように足すのではありません。",next:"n2"},{id:"n3",type:"explain",text:"次に「d個余る」を考えます。余りは、配った分に足すとはじめの個数に戻ります。",next:"n4"},{id:"n4",type:"check",question:"はじめの個数を表す式はどれ？",choices:["4c-d","4c+d"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"「余る」は配った後に残っている量なので、はじめの個数に含まれます。配った分に足す必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：配った個数4cに余りdを足して (4c+d)個。積の関係と加える関係を正しく区別することがポイントでした。",next:"end"}]}},{id:"P0-MOJI-149",subunit:"数量を文字式で表す",difficulty:"★3応用",problem_text:"制限時間3時間の競技で開始からy分たったときの残り時間を[時間]で表しなさい。",answer:"(3 - y/60)時間",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この問題は「y分」という時間を「時間」の単位に変換してから、制限時間3時間との差を式にする問題です。",next:"n2"},{id:"n2",type:"check",question:"y分を時間の単位に直すには、yをどうする？",choices:["yに60をかける","yを60で割る"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1時間=60分なので、分を時間に直すには60で割ります。y分=y/60時間です。60をかけると単位が逆に大きくなってしまいます。",next:"n2"},{id:"n3",type:"explain",text:"y分=y/60時間となります。この分数の書き方も、y/60を1つのまとまりとして正しく書くことが大切です。",next:"n4"},{id:"n4",type:"check",question:"残り時間はどんな式で表す？",choices:["3-y/60","3-y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"yは分の単位のままなので、時間の単位に変換したy/60を使う必要があります。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：単位変換してから引き算する。制限時間3時間から経過時間y/60時間を引いて (3-y/60)時間 が正解です。",next:"end"}]}},{id:"P0-MOJI-150",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"-y÷8",answer:"-y/8",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字式の表記ルールでは、÷の記号は使わず分数の形で表します。",next:"n2"},{id:"n2",type:"check",question:"-y÷8 を分数の形にすると、÷はどこに置き換わる？",choices:["数字の位置に書く（-y8）","分数の線（-y/8）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷の記号を消して数字を並べるだけでは意味が変わってしまいます。÷は分数の線に直します。",next:"n2"},{id:"n3",type:"explain",text:"-y÷8を分数にすると -y/8 です。符号のマイナスは分子側にまとめて書きます。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：文字式では÷を使わず分数で表す。符号は前にまとめる。-y÷8 = -y/8 が正解です。",next:"end"}]}},{id:"P0-MOJI-151",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"z÷(-9)",answer:"-z/9",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"z÷(-9)を文字式の表記ルールで表す問題です。÷を分数に直すことと、符号の処理の2つがポイントです。",next:"n2"},{id:"n2",type:"check",question:"z÷(-9)を分数の形にすると、符号（マイナス）はどこに置くのが正しい表記？",choices:["分母に残す（z/-9）","分数の前にまとめる（-z/9）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分母にマイナスを残すのは正しい表記ではありません。符号は分数全体の前にまとめて書きます。",next:"n2"},{id:"n3",type:"explain",text:"符号をまとめると -z/9 になります。分母は9という正の数だけにします。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：÷は分数に直し、符号は前にまとめる。z÷(-9) = -z/9 が正解です。",next:"end"}]}},{id:"P0-MOJI-152",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"(x+y)÷4",answer:"(x+y)/4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(x+y)÷4を文字式の表記ルールで表す問題です。かっこ全体が4で割られることを意識します。",next:"n2"},{id:"n2",type:"check",question:"(x+y)÷4を分数にすると、分子に置くのは？",choices:["yだけ","x+y全体"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"かっこは中身全体をひとまとまりとして扱う印です。4で割るのはx+y全体です。",next:"n2"},{id:"n3",type:"explain",text:"分子に(x+y)、分母に4を置くと (x+y)/4 になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：かっこ全体を分子に、割る数を分母に置く。(x+y)÷4 = (x+y)/4 が正解です。",next:"end"}]}},{id:"P0-MOJI-153",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"7y÷3",answer:"7y/3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"7y÷3を文字式の表記ルールで表す問題です。÷を分数に直すことがポイントです。",next:"n2"},{id:"n2",type:"check",question:"7y÷3 を分数の形にすると？",choices:["7y3","7y/3"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷の記号を消して数字を並べるだけでは意味が変わります。÷は分数の線に直します。",next:"n2"},{id:"n3",type:"explain",text:"7y/3になります。7と3は公約数がないので、これ以上約分できません。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：÷を分数に直し、約分できるか確認する。7y÷3 = 7y/3 が正解です。",next:"end"}]}},{id:"P0-MOJI-154",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"-8y÷(-4)",answer:"2y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-8y÷(-4)を計算する問題です。符号の処理と約分の2つのステップがあります。",next:"n2"},{id:"n2",type:"check",question:"負の数を負の数で割ると、符号はどうなる？",choices:["負のまま","正になる"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"負÷負は正になります。符号だけ先に決めておくと計算しやすくなります。",next:"n2"},{id:"n3",type:"explain",text:"符号は正なので、-8y÷(-4)=8y÷4と考えられます。あとは数の部分を約分します。",next:"n4"},{id:"n4",type:"check",question:"8y÷4を約分すると？",choices:["8y/4のまま","2y"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"8と4は4で約分できます。8÷4=2なので、8y/4=2yまで簡単にします。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：符号を先に決め、数を約分する。-8y÷(-4) = 2y が正解です。",next:"end"}]}},{id:"P0-MOJI-155",subunit:"文字式の表記ルール（商）",difficulty:"★1基礎",problem_text:"(y-2)÷(-5)",answer:"-(y-2)/5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(y-2)÷(-5)を文字式の表記ルールで表す問題です。かっこの中身を変えずに符号だけ処理することがポイントです。",next:"n2"},{id:"n2",type:"check",question:"符号を分数の前に出すとき、かっこの中の符号（y-2）はどうなる？",choices:["y+2に変わる","y-2のまま変わらない"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を外に出すのは全体にかかる1つの符号だけです。かっこの中の項どうしの符号は変わりません。",next:"n2"},{id:"n3",type:"explain",text:"かっこの中身はそのまま(y-2)、符号は前にまとめて-にします。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：かっこの中身は変えず、符号だけ前にまとめる。(y-2)÷(-5) = -(y-2)/5 が正解です。",next:"end"}]}},{id:"P0-MOJI-156",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"3×y÷7",answer:"3y/7",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3×y÷7を文字式の表記ルールで表す問題です。×の省略と÷の分数化、2つのルールを順番に使います。",next:"n2"},{id:"n2",type:"check",question:"3×yの×を省略すると？",choices:["y3","3y"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字式では数を文字の前に書きます。3×yは3yと表します。",next:"n2"},{id:"n3",type:"explain",text:"3yになったら、次は÷7を分数の形に直します。",next:"n4"},{id:"n4",type:"check",question:"3y÷7を分数の形にすると？",choices:["3y7","3y/7"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"÷の記号を消して数字を並べるだけでは意味が変わります。÷は分数の線に直します。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：×を省略してから÷を分数にする。3×y÷7 = 3y/7 が正解です。",next:"end"}]}},{id:"P0-MOJI-157",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"x×4×(-y)",answer:"-4xy",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"x×4×(-y)を文字式の表記ルールで表す問題です。数の位置、文字の順序、符号の3つを整理します。",next:"n2"},{id:"n2",type:"check",question:"符号（マイナス）はいくつある？全体の符号は？",choices:["1個で、全体は負","0個で、全体は正"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"(-y)の中にマイナスが1個あります。マイナスが奇数個あると全体は負になります。",next:"n2"},{id:"n3",type:"explain",text:"全体は負とわかったら、数を前、文字をアルファベット順に並べます。",next:"n4"},{id:"n4",type:"check",question:"数と文字の正しい並べ方は？",choices:["-4xy（数→x→y）","-4yx（数→y→x）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字式では文字をアルファベット順に並べます。xはyより先なので、xyの順です。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：符号を先に決め、数を前、文字をアルファベット順に並べる。x×4×(-y) = -4xy が正解です。",next:"end"}]}},{id:"P0-MOJI-158",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"y×y÷6",answer:"y²/6",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"y×y÷6を文字式の表記ルールで表す問題です。同じ文字の積と÷の分数化、2つのルールを使います。",next:"n2"},{id:"n2",type:"check",question:"y×yはどう表す？",choices:["2y（2倍）","y²（累乗）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"y×yは同じ文字どうしのかけ算なので累乗y²で表します。2y（y+yの意味）とは違います。",next:"n2"},{id:"n3",type:"explain",text:"y×y=y²になったら、次は÷6を分数の形に直します。",next:"n4"},{id:"n4",type:"check",question:"y²÷6を分数の形にすると？",choices:["y²÷6のまま","y²/6"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"文字式では÷の記号は使わず分数の形にします。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：同じ文字の積は累乗、÷は分数にする。y×y÷6 = y²/6 が正解です。",next:"end"}]}},{id:"P0-MOJI-159",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"9÷y÷2",answer:"9/(2y)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"9÷y÷2を文字式の表記ルールで表す問題です。÷が2回続く場合の処理がポイントです。",next:"n2"},{id:"n2",type:"check",question:"9÷y÷2は、9をどうすることと同じ？",choices:["yと2の両方で割る","yで割ってから2をかける"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷が続くときは、後ろの数をすべて分母にまとめて割ることになります。9÷y÷2は9をyと2の両方で割るのと同じです。",next:"n2"},{id:"n3",type:"explain",text:"分母にyと2をまとめて書くと2yになります。これを分数の形にします。",next:"n4"},{id:"n4",type:"check",question:"9÷y÷2を1つの分数で表すと？",choices:["9/y/2","9/(2y)"],correct:1,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"分数を2段に重ねるのではなく、分母にy×2をまとめて1つの分数にします。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：連続する÷は分母にまとめて1つの分数にする。9÷y÷2 = 9/(2y) が正解です。",next:"end"}]}},{id:"P0-MOJI-160",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"(-3)×y+8÷z",answer:"-3y+8/z",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(-3)×y+8÷zを文字式の表記ルールで表す問題です。積の項と商の項、それぞれ別のルールを使い、最後に符号ごとつなげます。",next:"n2"},{id:"n2",type:"check",question:"(-3)×yはどう表す？",choices:["-3y","3y"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"項は符号込みのかたまりです。(-3)×yの符号マイナスは省略せず、-3yと書きます。",next:"n2"},{id:"n3",type:"explain",text:"-3yになったら、次に8÷zを分数の形にします。",next:"n4"},{id:"n4",type:"check",question:"8÷zを分数の形にすると？",choices:["8/z","z/8"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"÷の左側（8）が分子、右側（z）が分母になります。8÷z=8/zです。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：積の項は数を前に、商の項は分数にして、符号込みでつなげる。(-3)×y+8÷z = -3y+8/z が正解です。",next:"end"}]}},{id:"P0-MOJI-161",subunit:"文字式の表記ルール（商）",difficulty:"★2標準",problem_text:"4×(x+y)÷z を、文字式の表し方の約束にしたがって書きなさい。",answer:"4(x+y)/z",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4×(x+y)÷z には×と÷が混ざっています。まず×の部分から片づけましょう。4×(x+y) は数を前に、×を省略して 4(x+y) と書けます。",next:"n2"},{id:"n2",type:"check",question:"残った 4(x+y)÷z の÷を書き換えるとき、正しいのはどっち？",choices:["4(x+y)z（÷も×と同じように消すだけ）","4(x+y)/z（分数の形にしてzを分母に置く）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"÷は×とちがい、記号を消すだけではいけません。÷は分数の形に直し、割る数（z）を分母に置くのがルールです。",next:"n2"},{id:"n3",type:"explain",text:"そのとおりです。÷zは分数の形にして、zを分母に書きます。4(x+y)÷z → 4(x+y)/z となります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：×は省略して数を前に、÷は分数にして分母に置く。この2つのルールを順番に使えば、積と商が混ざった式も正しく表せます。",next:"end"}]}},{id:"P0-MOJI-162",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"y×7 を、文字式の表し方の約束にしたがって書きなさい。",answer:"7y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字式では×を省略します。ただし省略したあとの並べ方にも約束があります。",next:"n2"},{id:"n2",type:"check",question:"y×7 の×を省略するとき、正しい書き方はどっち？",choices:["y7（書かれていた順のまま）","7y（数を文字の前に書く）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。文字式の約束では「数を文字の前」に書きます。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。数の7を文字yの前に置くので、y×7 → 7y になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：×を省略するだけでなく、数を文字の前に並べ替えることも忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-163",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"z×y×x を、文字式の表し方の約束にしたがって書きなさい。",answer:"xyz",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"文字どうしのかけ算では×を省略します。ただし文字の並べる順番にも約束があります。",next:"n2"},{id:"n2",type:"check",question:"z×y×x の×を省略するとき、正しい書き方はどっち？",choices:["zyx（書かれていた順のまま）","xyz（アルファベット順に並べ替える）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。文字式では文字をアルファベット順に並べるのが約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。z, y, x をアルファベット順に並べ替えると xyz になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：文字が複数あるときは、×を省略したあとアルファベット順に並べ替えることを忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-164",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"3/8×(p−q) を、文字式の表し方の約束にしたがって書きなさい。",answer:"3/8(p-q)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3/8×(p-q) では、分数の係数3/8がもともとかっこの前にあります。×を省略するだけで済むか確かめましょう。",next:"n2"},{id:"n2",type:"check",question:"3/8×(p-q) の×を省略した正しい書き方はどっち？",choices:["3/8(p-q)（×を消してそのまま）","(p-q)3/8（かっこを前に並べ替える）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"数（分数の係数）はもともとかっこの前にあるので、並べ替える必要はありません。×を省略するだけでよいのです。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。3/8はすでに前にあるので、×を消すだけで 3/8(p-q) になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：数がすでにかっこの前にあるときは、×を省略するだけでよく、かっこの中の符号も変えないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-165",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"(m+n)×(-0.3) を、文字式の表し方の約束にしたがって書きなさい。",answer:"-0.3(m+n)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(m+n)×(-0.3) では、かっこが先、数が後に書かれています。×を省略するとき、並べ替えが必要です。",next:"n2"},{id:"n2",type:"check",question:"(m+n)×(-0.3) の×を省略した正しい書き方はどっち？",choices:["(m+n)(-0.3)（書かれていた順のまま）","-0.3(m+n)（数を前に並べ替える）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。数（-0.3）を文字・かっこより前に並べ替えるのが約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。数の-0.3をかっこの前に置くので、(m+n)×(-0.3) → -0.3(m+n) になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：かっこが先に書かれていても、数は必ず前に並べ替えます。マイナスの符号を落とさないことも大切です。",next:"end"}]}},{id:"P0-MOJI-166",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"0.7×y を、文字式の表し方の約束にしたがって書きなさい。",answer:"0.7y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"0.7×y では、数0.7がすでに文字yの前に書かれています。×を省略するだけで正しい形になるか確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"0.7×y の×を省略した正しい書き方はどっち？",choices:["0.7y（×を消してそのまま）","y0.7（文字を前に並べ替える）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"数はすでに文字の前にあるので、並べ替える必要はありません。×を省略するだけでよいのです。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。0.7×y → 0.7y となります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：数がすでに文字の前にあるときは、×を省略するだけで完成です。小数の係数もそのまま前に置きます。",next:"end"}]}},{id:"P0-MOJI-167",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"1×m を、文字式の表し方の約束にしたがって書きなさい。",answer:"m",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"1×m では×を省略します。ただし係数が1のときには、さらに特別な約束があります。",next:"n2"},{id:"n2",type:"check",question:"1×m の×を省略するとき、正しい書き方はどっち？",choices:["1m（1を書いたまま残す）","m（係数1を省略する）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1を書いたまま残してはいけません。係数が1のときは、その1を省略するのが文字式の約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。係数1は省略するので、1×m → m になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：×を省略するだけでなく、係数が1のときはその1も省略することを忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-168",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"5×(b+3) を、文字式の表し方の約束にしたがって書きなさい。",answer:"5(b+3)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5×(b+3) では、数5がすでにかっこの前に書かれています。×を省略するだけで正しい形になるか確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"5×(b+3) の×を省略した正しい書き方はどっち？",choices:["5(b+3)（×を消してそのまま）","5b+3（かっこの中の最初の項だけにかける）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"5b+3は、5をbだけにかけて3にかけていません。この問題はまだ「表記」の段階なので、かっこの中は計算せずそのまま残します。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。かっこの中は計算せず、×を消すだけで 5(b+3) になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：数がすでにかっこの前にあるときは×を省略するだけでよく、かっこの中を勝手に計算しないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-169",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"(p−q)×(−4) を、文字式の表し方の約束にしたがって書きなさい。",answer:"-4(p-q)",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"(p-q)×(-4) では、かっこが先、数が後に書かれています。×を省略するとき、並べ替えが必要です。",next:"n2"},{id:"n2",type:"check",question:"(p-q)×(-4) の×を省略した正しい書き方はどっち？",choices:["(p-q)(-4)（書かれていた順のまま）","-4(p-q)（数を前に並べ替える）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。数（-4）を文字・かっこより前に並べ替えるのが約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。数の-4をかっこの前に置くので、(p-q)×(-4) → -4(p-q) になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：かっこが先に書かれていても、数は必ず前に並べ替えます。マイナスの符号を落とさないことも大切です。",next:"end"}]}},{id:"P0-MOJI-170",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"x×y×0.2 を、文字式の表し方の約束にしたがって書きなさい。",answer:"0.2xy",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"x×y×0.2 には文字が2つと数が1つあります。×をすべて省略したあと、正しい順に並べ替える約束があります。",next:"n2"},{id:"n2",type:"check",question:"x×y×0.2 の×を省略した正しい書き方はどっち？",choices:["xy0.2（書かれていた順のまま）","0.2xy（数を先頭、文字をアルファベット順に）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。数は先頭に、文字はアルファベット順に並べ替えるのが約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。数0.2を先頭に、x, yをアルファベット順に並べるので、x×y×0.2 → 0.2xy になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：数がどこに書かれていても先頭に、文字は複数あればアルファベット順に並べ替えることを忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-171",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"-8×m を、文字式の表し方の約束にしたがって書きなさい。",answer:"-8m",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"-8×m では、数-8がすでに文字mの前に書かれています。×を省略するだけで正しい形になるか確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"-8×m の×を省略した正しい書き方はどっち？",choices:["-8m（符号をつけたまま、×を消す）","8m（符号を落として×を消す）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"符号を落としてはいけません。マイナスの符号は数字にくっついたまま、そのまま残します。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。符号をつけたまま×を消すので、-8×m → -8m になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：負の数の係数は、符号込みでそのまま文字の前に置きます。符号を落とさないよう注意しましょう。",next:"end"}]}},{id:"P0-MOJI-172",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"2/5×y を、文字式の表し方の約束にしたがって書きなさい。",answer:"2/5 y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"2/5×y では、分数の係数2/5がすでに文字yの前に書かれています。×を省略するだけで正しい形になるか確認しましょう。",next:"n2"},{id:"n2",type:"check",question:"2/5×y の×を省略した正しい書き方はどっち？",choices:["2/5 y（×を消してそのまま）","y2/5（文字を前に並べ替える）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"数（分数の係数）はすでに文字の前にあるので、並べ替える必要はありません。×を省略するだけでよいのです。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。2/5×y → 2/5 y となります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：分数の係数がすでに文字の前にあるときは、×を省略するだけで完成です。",next:"end"}]}},{id:"P0-MOJI-173",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"b×(-1) を、文字式の表し方の約束にしたがって書きなさい。",answer:"-b",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"b×(-1) では×を省略します。係数が-1のときには、1だけを省略し符号は残すという特別な約束があります。",next:"n2"},{id:"n2",type:"check",question:"b×(-1) の×を省略するとき、正しい書き方はどっち？",choices:["-1b（1を書いたまま残す）","-b（1を省略し符号だけ残す）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"1を書いたまま残してはいけません。係数が-1のときは、1を省略して符号（マイナス）だけを残すのが約束です。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。係数-1は1を省略し符号だけ残すので、b×(-1) → -b になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：係数が-1のときは、1を消しても符号（マイナス）は消さずに残すことを忘れないようにしましょう。",next:"end"}]}},{id:"P0-MOJI-174",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"5×p+5×q を、文字式の表し方の約束にしたがって書きなさい。",answer:"5p+5q",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5×p+5×q には項が2つあります。それぞれの項ごとに×を省略します。5×p → 5p、5×q → 5q です。",next:"n2"},{id:"n2",type:"check",question:"5p+5qのように係数が同じ項が2つあるとき、正しい扱いはどっち？",choices:["10pqのように数どうし・文字どうしをまとめる","5p+5qのまま、+でつないで残す"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数が同じでも、pとqは異なる文字なのでまとめることはできません。同じ文字（同類項）どうしでなければ合わせられないのです。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。pとqは違う文字なので、5p+5qのまま+でつないで残します。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：項ごとに×を省略したあと、異なる文字の項は勝手にまとめず、+でつないだ形のままにしましょう。",next:"end"}]}},{id:"P0-MOJI-175",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"b×(-9)+1×c を、文字式の表し方の約束にしたがって書きなさい。",answer:"-9b+c",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"b×(-9)+1×c には項が2つあります。それぞれの項に、これまで学んだルールを別々に適用します。",next:"n2"},{id:"n2",type:"check",question:"1つ目の項 b×(-9) を正しく表すとどっち？",choices:["b-9（書かれていた順のまま）","-9b（数を前に、符号もつけて）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"書かれていた順のままではいけません。数は文字の前に、マイナスの符号もつけたまま置きます。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。b×(-9) → -9b です。次に2つ目の項1×cを見てみましょう。係数1は省略するので1×c → cです。",next:"n4"},{id:"n4",type:"check",question:"-9bとcを合わせるとき、正しい形はどっち？",choices:["-9b+c（+でつなぐ）","-9bc（かけ合わせてまとめる）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"bとcは異なる文字なので、かけ合わせてまとめることはできません。+でつないだ形のまま残します。",next:"n4"},{id:"n5",type:"explain",text:"まとめ：各項ごとに×の省略・係数1の省略・符号の処理を行い、異なる文字の項は+でつないだまま残します。b×(-9)+1×c → -9b+c です。",next:"end"}]}},{id:"P0-MOJI-176",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"p-q×r を、文字式の表し方の約束にしたがって書きなさい。",answer:"p-qr",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"p-q×r には、-（ひき算）と×（かけ算）が混ざっています。×がある部分だけを略記のルールで処理します。",next:"n2"},{id:"n2",type:"check",question:"p-q×r を正しく表すとどっち？",choices:["p-q-r（×も-に変えてしまう）","p-qr（q×rだけを略記し、pはそのまま残す）"],correct:1,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"×を-に変えてはいけません。×がある部分（q×r）だけを略記してqrとし、-の前の項pはそのまま残します。",next:"n2"},{id:"n3",type:"explain",text:"そのとおり。q×r → qrと略記し、pの前の-とpはそのまま残るので、p-q×r → p-qr になります。",next:"n4"},{id:"n4",type:"explain",text:"まとめ：式の中で×がある部分だけを表記ルールで処理し、+や-でつながれた他の項はそのまま残します。",next:"end"}]}},{id:"P0-MOJI-177",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"-3×p-q×(-1)",answer:"-3p+q",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この式は -3×p と -q×(-1) の2つの項に分けて考えます。まず -3×p を計算しましょう。",next:"n2"},{id:"n2",type:"check",question:"-3×p はどう表せる？",choices:["-3p","3p"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数の-3をそのまま前に出して文字pを続けます。-3×p=-3pです。",next:"n2"},{id:"n3",type:"explain",text:"次に -q×(-1) を考えます。q×(-1)=-q ですが、これはもともとの式の - と合わせて考える必要があります。",next:"n4"},{id:"n4",type:"check",question:"-q×(-1) の符号はどうなる？",choices:["+q（符号が変わる）","-q（符号は変わらない）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"マイナスが2回かけ合わさると符号は変わります。-q×(-1)=+qです。マイナスの個数を数える癖をつけましょう。",next:"n4"},{id:"n5",type:"explain",text:"2つの項をまとめると -3p+q。pとqは違う文字なので、これ以上まとめられません。これが答えです。",next:"end"}]}},{id:"P0-MOJI-178",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"p×q+r×s-t×u",answer:"pq+rs-tu",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この式にはp×q、r×s、t×uという3つの積と、それをつなぐ+、-の記号があります。",next:"n2"},{id:"n2",type:"check",question:"文字式の表記ルールで省略してよい記号は？",choices:["×だけ","×と+と-すべて"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"省略できるのは×だけです。+とーは項をつなぐ大事な記号なので残します。",next:"n2"},{id:"n3",type:"explain",text:"p×q→pq、r×s→rs、t×u→tuと、それぞれの×だけを消します。",next:"n4"},{id:"n4",type:"check",question:"間の+と-はどうする？",choices:["そのまま残す","全部消す"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"+とーは項の区切りとして必要です。消さずに残しましょう。",next:"n4"},{id:"n5",type:"explain",text:"つなげると pq+rs-tu になります。これが答えです。",next:"end"}]}},{id:"P0-MOJI-179",subunit:"文字式の表記ルール（積）",difficulty:"★1基礎",problem_text:"a×(-1)×b-1×c",answer:"-ab-c",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"この式には a×(-1)×b という項と 1×c という項があります。まずa×(-1)×bを考えます。",next:"n2"},{id:"n2",type:"check",question:"係数が-1のとき、数字の1はどう書く？",choices:["省略して-abと書く","-1abとそのまま書く"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数1（や-1）は数字を省略するのがルールです。a×(-1)×b=-abと書きます。",next:"n2"},{id:"n3",type:"explain",text:"次に1×cを考えます。係数1も同じように省略します。",next:"n4"},{id:"n4",type:"check",question:"1×cの前についている-はどう扱う？",choices:["cの符号として残し-cにする","-は消えてcだけにする"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"-1×cのように考えると、係数1を省略しても符号のーは残ります。-cです。",next:"n4"},{id:"n5",type:"explain",text:"2つの項をまとめると -ab-c。これが答えです。",next:"end"}]}},{id:"P0-MOJI-180",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"p×q×p×q",answer:"p²q²",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"p×q×p×qには、pが2個、qが2個かけ合わされています。まずこれを数えてみましょう。",next:"n2"},{id:"n2",type:"check",question:"同じ文字を2個かけ合わせたとき、正しい表し方は？",choices:["累乗で表す（p×p=p²）","係数をつけて2倍にする（p×p=2p）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"「2個並んでいる」は「2倍」ではなく「2乗」です。かけ算の回数が指数になります。p×p=p²です。2pはp+pの意味なので違います。",next:"n2"},{id:"n3",type:"explain",text:"同じようにqも2個かけ合わされているのでq×q=q²です。",next:"n4"},{id:"n4",type:"check",question:"p²とq²を合わせて書くとどうなる？",choices:["p²q²","2p2q"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"係数の2を書き足す必要はありません。それぞれの累乗をそのまま並べます。",next:"n4"},{id:"n5",type:"explain",text:"p²とq²をそのまま並べて p²q² が答えです。",next:"end"}]}},{id:"P0-MOJI-181",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"y×8×y",answer:"8y²",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"y×8×yは、数の8と文字yが混ざった順で並んでいます。まず並べ替えます。",next:"n2"},{id:"n2",type:"check",question:"数と文字はどちらを前に書く約束だった？",choices:["数を前、文字を後ろ","書かれた順のまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"文字式のルールでは数を前に、文字を後ろにそろえます。8×y×yと並べ替えましょう。",next:"n2"},{id:"n3",type:"explain",text:"8×y×yのy×yの部分、同じ文字が2個かけられています。",next:"n4"},{id:"n4",type:"check",question:"y×yはどう表す？",choices:["y²","2y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"同じ文字を2個かけたときは累乗で表します。y×y=y²です。2yはy+yの意味なので違います。",next:"n4"},{id:"n5",type:"explain",text:"8とy²をつなげて 8y² が答えです。",next:"end"}]}},{id:"P0-MOJI-182",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"b×b×(-5)×b",answer:"-5b³",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"b×b×(-5)×bには数の-5と文字bが混ざった順で並んでいます。まず並べ替えます。",next:"n2"},{id:"n2",type:"check",question:"数の-5はどこに書く？",choices:["先頭に","元の位置のまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"数を前にそろえます。(-5)×b×b×bと並べ替えましょう。",next:"n2"},{id:"n3",type:"explain",text:"b×b×bの部分、同じ文字が3個かけられています。",next:"n4"},{id:"n4",type:"check",question:"b×b×bはどう表す？",choices:["b³","3b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"「3個かける」は「3倍」ではなく「3乗」です。b×b×b=b³です。3bはb+b+bの意味なので違います。",next:"n4"},{id:"n5",type:"explain",text:"-5とb³をつなげて -5b³ が答えです。",next:"end"}]}},{id:"P0-MOJI-183",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"p×q×p×(-1)",answer:"-p²q",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"p×q×p×(-1)には係数-1と文字p、qが混ざった順で並んでいます。まず並べ替えます。",next:"n2"},{id:"n2",type:"check",question:"係数-1をどこに、どう書く？",choices:["先頭に、数字の1は省略して-だけ","先頭に、-1とそのまま書く"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数1（や-1）は数字を省略します。(-1)×p×p×qと並べ替えても、最終的に書くときは符号だけ残します。",next:"n2"},{id:"n3",type:"explain",text:"次にp×pの部分、同じ文字が2個かけられています。",next:"n4"},{id:"n4",type:"check",question:"p×pはどう表す？",choices:["p²","2p"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"「2個かける」は「2乗」です。p×p=p²です。2pはp+pの意味なので違います。",next:"n4"},{id:"n5",type:"explain",text:"符号の-、p²、qをつなげて -p²q が答えです（係数1は省略）。",next:"end"}]}},{id:"P0-MOJI-184",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"b×b×(-0.4)",answer:"-0.4b²",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"b×b×(-0.4)には数の-0.4と文字bが混ざった順で並んでいます。まず並べ替えます。",next:"n2"},{id:"n2",type:"check",question:"小数の係数でも、数を前にそろえる手順は変わる？",choices:["変わらない、同じ手順","小数のときは別の手順になる"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数が小数でも整数でも手順は同じです。数を前にそろえます。(-0.4)×b×bです。",next:"n2"},{id:"n3",type:"explain",text:"b×bの部分、同じ文字が2個かけられています。",next:"n4"},{id:"n4",type:"check",question:"b×bはどう表す？",choices:["b²","2b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"「2個かける」は「2乗」です。b×b=b²です。2bはb+bの意味なので違います。",next:"n4"},{id:"n5",type:"explain",text:"-0.4とb²をつなげて -0.4b² が答えです。",next:"end"}]}},{id:"P0-MOJI-185",subunit:"文字式の表記ルール（積）",difficulty:"★2標準",problem_text:"x×(-1/3)×x×x",answer:"-1/3 x³",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"x×(-1/3)×x×xには数の-1/3と文字xが混ざった順で並んでいます。まず並べ替えます。",next:"n2"},{id:"n2",type:"check",question:"数の-1/3はどこに書く？",choices:["先頭に","元の位置のまま"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"数を前にそろえます。(-1/3)×x×x×xと並べ替えましょう。",next:"n2"},{id:"n3",type:"explain",text:"残ったx×x×xの部分、xが何個あるか数えます。",next:"n4"},{id:"n4",type:"check",question:"xは何個かけ合わされている？",choices:["3個（x³）","2個（x²）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"元の式を見直すとxはx×(-1/3)×x×xの中に3か所あります。数え間違えないよう1つずつ指で数えましょう。x×x×x=x³です。",next:"n4"},{id:"n5",type:"explain",text:"-1/3とx³をつなげて -1/3 x³ が答えです。",next:"end"}]}},{id:"P0-MOJI-186",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"3y²",answer:"3×y×y",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3y²を×を使った形に戻します。まず係数3を考えます。",next:"n2"},{id:"n2",type:"check",question:"係数3はどう書く？",choices:["3×…と×を補う","そのまま3だけ"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"省略されていた×の記号を補います。3×…と書きます。",next:"n2"},{id:"n3",type:"explain",text:"次にy²を考えます。指数の2は「同じ文字を2回かけた」ことを表します。",next:"n4"},{id:"n4",type:"check",question:"y²を×の形に戻すとどうなる？",choices:["y×y","2×y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"指数の2は掛け算の相手の数字ではなく「かけた回数」です。y²=y×yと戻します。",next:"n4"},{id:"n5",type:"explain",text:"3×とy×yをつなげて 3×y×y が答えです。",next:"end"}]}},{id:"P0-MOJI-187",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"4pq²",answer:"4×p×q×q",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4pq²を×を使った形に戻します。この式にはpが1乗、qが2乗で混ざっています。",next:"n2"},{id:"n2",type:"check",question:"係数4とpはどう書く？",choices:["4×p×…","4×2×p×…"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"係数4に×を補い、pは1乗なのでそのまま1回続けます。4×p×…です。",next:"n2"},{id:"n3",type:"explain",text:"次にq²を考えます。指数2は「qを2回かけた」ことを表します。",next:"n4"},{id:"n4",type:"check",question:"q²を×の形に戻すとどうなる？",choices:["q×q（2個書く）","q（1個だけ）"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"指数2を忘れずに、qを2回書きます。q²=q×qです。1個だけ書くと指数を無視したことになります。",next:"n4"},{id:"n5",type:"explain",text:"4×p×とq×qをつなげて 4×p×q×q が答えです。",next:"end"}]}},{id:"P0-MOJI-188",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"5y/4",answer:"5×y÷4",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"5y/4を×と÷の記号を使った形に戻します。分数の線には意味があります。",next:"n2"},{id:"n2",type:"check",question:"分数の形（分子/分母）は何算の省略？",choices:["分子÷分母の÷が省略されている","分子×分母の×が省略されている"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数は「分子÷分母」の意味です。5y/4は5y÷4に戻せます。",next:"n2"},{id:"n3",type:"explain",text:"5y÷4の5yの部分は、さらに数と文字に分けられます。",next:"n4"},{id:"n4",type:"check",question:"5yをさらに分けるとどうなる？",choices:["5×y","5+y"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"5yは5×yの×が省略された形です。5×yに戻します。",next:"n4"},{id:"n5",type:"explain",text:"5×yと÷4をつなげて 5×y÷4 が答えです。",next:"end"}]}},{id:"P0-MOJI-189",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"3(p+q)/7",answer:"3×(p+q)÷7",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"3(p+q)/7を×と÷の記号を使った形に戻します。分数の線には意味があります。",next:"n2"},{id:"n2",type:"check",question:"分数の形（分子/分母）は何算の省略？",choices:["分子÷分母の÷が省略されている","分子×分母の×が省略されている"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数は「分子÷分母」の意味です。3(p+q)/7は3(p+q)÷7に戻せます。",next:"n2"},{id:"n3",type:"explain",text:"3(p+q)÷7の3(p+q)の部分は、さらに数とかっこに分けられます。",next:"n4"},{id:"n4",type:"check",question:"3(p+q)を分けるとき、かっこの中身(p+q)はどうする？",choices:["崩さず一つの塊のまま残す","3をpだけにかけてqは別にする"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"外の数3はかっこの中身全体にかかっています。(p+q)は崩さず、3×(p+q)とまとめて書きます。",next:"n4"},{id:"n5",type:"explain",text:"3×(p+q)と÷7をつなげて 3×(p+q)÷7 が答えです。",next:"end"}]}},{id:"P0-MOJI-190",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"ab/5",answer:"a×b÷5",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"ab/5を×と÷の記号を使った形に戻します。分数の線には意味があります。",next:"n2"},{id:"n2",type:"check",question:"分数の形（分子/分母）は何算の省略？",choices:["分子÷分母の÷が省略されている","分子×分母の×が省略されている"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"分数は「分子÷分母」の意味です。ab/5はab÷5に戻せます。",next:"n2"},{id:"n3",type:"explain",text:"ab÷5のabの部分は、さらに文字どうしの積に分けられます。",next:"n4"},{id:"n4",type:"check",question:"abをさらに分けるとどうなる？",choices:["a×b","a+b"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"abはa×bの×が省略された形です。a×bに戻します。",next:"n4"},{id:"n5",type:"explain",text:"a×bと÷5をつなげて a×b÷5 が答えです。",next:"end"}]}},{id:"P0-MOJI-191",subunit:"記号×÷で表す（逆変換）",difficulty:"★2標準",problem_text:"4pq+r/3",answer:"4×p×q+r÷3",teacher_mode:{start:"n1",nodes:[{id:"n1",type:"explain",text:"4pq+r/3には+で区切られた2つの項、4pqとr/3があります。それぞれ別々に処理します。",next:"n2"},{id:"n2",type:"check",question:"4pqはどう分ける？",choices:["4×p×q（係数と文字それぞれ×でつなぐ）","4×pq（pqはそのまま残す）"],correct:0,onCorrect:"n3",onWrong:"n2r"},{id:"n2r",type:"explain",text:"4pqは係数4と文字p、文字qの積です。すべて×でつないで4×p×qと分けます。",next:"n2"},{id:"n3",type:"explain",text:"次にr/3の項を考えます。分数の形です。",next:"n4"},{id:"n4",type:"check",question:"r/3はどう戻す？",choices:["r÷3（分子÷分母）","r×3"],correct:0,onCorrect:"n5",onWrong:"n4r"},{id:"n4r",type:"explain",text:"分数は「分子÷分母」の意味です。r/3=r÷3に戻します。",next:"n4"},{id:"n5",type:"explain",text:"2つの項をつなげて 4×p×q+r÷3 が答えです。",next:"end"}]}}],i={unit:e,count:191,problems:n};export{t as count,i as default,n as problems,e as unit};
